-- 자동 생성 파일 (scripts/generate-seed-sql.ts). 07/08
-- 001_ingredients.sql을 먼저 실행한 뒤 순서대로 실행하세요.
insert into public.recipes_cache
  (id, name, category, raw_ingredients_text, parsed_ingredients, matched_ingredient_ids, cooking_steps, image_url,
   nutrition_kcal, nutrition_carb, nutrition_protein, nutrition_fat, nutrition_sodium)
values
  ('1021', '스테이크 샐러드', '반찬', '쇠고기등심 80g, 로메인 30g, 워터크레스 2g, 래디쉬 5g, 방울토마토 10g, 레드어니언 8g, 발사믹식초 4g, 올리브오일 1g, 소금적당량, 통후추 적당량', '["쇠고기등심","로메인","워터크레스","래디쉬","방울토마토","레드어니언","발사믹식초","올리브오일","소금","통후추"]'::jsonb, ARRAY['1c49d1f4-5781-474d-818d-bd7002a4dc0b','f80c9a7d-1510-44e2-a82b-28b9f684e191','aa597bcd-596b-4cbe-a2c4-3da0d060cb50','6c285c60-022a-4a00-b172-87df97f16a2f','a8ac1f24-c286-4f4c-b9fc-d9b88b5d75dc','2cf0c12b-f248-4012-8f53-303c730a7b3d','bcb746cd-29c8-4bb2-93e4-5832b8adfa94']::uuid[], '[{"step":1,"text":"소고기등심에 소금, 후추로 간하고 팬에서 기호에 따라 굽는다. (스테이크 굽기 정도는 기호에 따라 조절한다.)","imageUrl":null},{"step":2,"text":"양파는 얇게 링으로 썰고 로메인은 적당한 크기로 찢고 래디쉬도 얇게 썰어 찬 물에 담궈둔다.","imageUrl":null},{"step":3,"text":"발사믹 식초에 올리브오일, 소금, 후추를 넣고 소스를 만든다. (기호에 따라 양파 다진 것 등을 첨가할 수 있다.)","imageUrl":null},{"step":4,"text":"2를 건져내 물기를 제거하고 소금, 후추로 간을 한다.","imageUrl":null},{"step":5,"text":"스테이크를 슬라이스 하여 접시에 앞 쪽에 담는다.","imageUrl":null},{"step":6,"text":"준비된 야채에 드래싱을 넣고 섞은 뒤 스테이크 옆에 담는다.","imageUrl":null}]'::jsonb, 'http://www.foodsafetykorea.go.kr/uploadimg/20141117/20141117053759_1416213479021.jpg', 177, 3.5, 17, 10.1, 404),
  ('1023', '씨앗죽', '밥', '쌀 30g, 참깨 3g, 통아몬드 4g, 땅콩 4g, 호박씨 4g, 물 90g, 소금 적당량', '["쌀","참깨","통아몬드","땅콩","호박씨","물","소금"]'::jsonb, ARRAY['a5bc0b46-0192-496a-b429-d2cb90b2bca9','9e00a5b9-84e6-4cdc-afb9-0ee2bd3342fc','02c78319-0bf6-45e0-8a7b-7546e1e47ba7','3d359f85-dafb-4490-a263-752f436e698b','94786475-832c-4f97-aab7-bf6fbbe2236b','2cf0c12b-f248-4012-8f53-303c730a7b3d']::uuid[], '[{"step":1,"text":"쌀을 깨끗이 씻어 5시간 정도 불린다.","imageUrl":null},{"step":2,"text":"불린 쌀을 절구에 넣어 쌀알이 반 정도 부서지도록 간다.","imageUrl":null},{"step":3,"text":"참깨, 아몬드, 땅콩, 호박씨를 믹서기에 간다.","imageUrl":null},{"step":4,"text":"냄비에 쌀과 물을 넣고 끓인다.","imageUrl":null},{"step":5,"text":"쌀알이 익으면 3의 씨앗가루를 넣고 끓인다.","imageUrl":null},{"step":6,"text":"소금간을 하고 준비한 그릇에 담아낸다.","imageUrl":null}]'::jsonb, 'http://www.foodsafetykorea.go.kr/uploadimg/20141117/20141117053801_1416213481209.jpg', 198, 27.3, 5.4, 7.9, 20),
  ('1024', '오븐에 구운 또띠아 칩과 아보카도 딥', '후식', '또띠아 25g, 양파다진것 5g, 할라피뇨다진것 2g, 마늘다진것 3g, 아보카도 12g, 라임주스 3g, 토마토 30g, 소금 적당량', '["또띠아","양파다진것","할라피뇨다진것","마늘다진것","아보카도","라임주스","토마토","소금"]'::jsonb, ARRAY['7ccfd335-1d3f-4e14-95b3-bd85ed08b72a','61a6a6cd-c3d6-4ba2-a033-f6e0b38bc742','fc6e31ce-388e-45cd-956b-b238b9134eb1','906bfef3-a41b-40d3-acda-7d8f23d2bcd2','aa597bcd-596b-4cbe-a2c4-3da0d060cb50','2cf0c12b-f248-4012-8f53-303c730a7b3d']::uuid[], '[{"step":1,"text":"또띠아는 6등분 한다.","imageUrl":null},{"step":2,"text":"양파, 할라피뇨, 마늘을 잘게 다진다.","imageUrl":null},{"step":3,"text":"아보카도는 껍질을 제거하고 토마토는 씨를 제거하여 각각 1cm 주사위모양으로 자른다.","imageUrl":null},{"step":4,"text":"170℃로 예열한 오븐에 또띠아를 넣어 바삭하게 굽는다.","imageUrl":null},{"step":5,"text":"볼에 2를 넣고 잘 섞어 페이스트를 만들다가 아보카도를 함께 넣고 으깬 후 토마토를 넣고 라임주스, 소금으로 맛을 낸다.","imageUrl":null},{"step":6,"text":"구워 낸 또띠아 칩을 찍어 먹을 수 있도록 아보카도딥을 작은 그릇에 담아낸다.","imageUrl":null}]'::jsonb, 'http://www.foodsafetykorea.go.kr/uploadimg/20141117/20141117053802_1416213482302.jpg', 139, 24.1, 2.6, 3.9, 40),
  ('1026', '참치 쇠고기 양상추 쌈', '반찬', '쇠고기 25g, 밥 60g, 상추 5g, 캔참치 5g 후추약간, 달걀흰자 10g, 간장 3g, 설탕 2g, 전분 2g 마요네즈 3g, 양파다진것 3g, 샐러리다진것 2g, 소금적당량, 설탕 적당량, 후춧가루 적당량', '["쇠고기","밥","상추","캔참치","달걀흰자","간장","설탕","전분","양파다진것","샐러리다진것","소금","후춧가루"]'::jsonb, ARRAY['1c49d1f4-5781-474d-818d-bd7002a4dc0b','ecb35816-34ae-4c4c-867a-e3f84db92755','1389717e-81e4-4350-96d4-d627d851aa10','c7d438a6-34d6-423f-905d-446b839e2f39','f175019d-5a93-4cd4-aabc-e7e79445f15a','06e6f3e7-0293-469d-a338-11a610f3e71b','6613d1d9-80a2-4ce4-9d3d-647203197e53','61a6a6cd-c3d6-4ba2-a033-f6e0b38bc742','12d2d4c9-705a-47f1-b628-30e042a970f8','2cf0c12b-f248-4012-8f53-303c730a7b3d','bcb746cd-29c8-4bb2-93e4-5832b8adfa94']::uuid[], '[{"step":1,"text":"소고기는 소금, 후추로 밑간을 하고 실파는 송송 썬다.","imageUrl":null},{"step":2,"text":"참치는 기름을 제거하고 양파, 셀러리, 마요네즈, 소금, 후추, 설탕을 넣고 양념한다.","imageUrl":null},{"step":3,"text":"상추는 작게 다듬어 얼음물에 담근다.","imageUrl":null},{"step":4,"text":"팬에 기름을 두르고 다진 마늘을 넣고 볶다가 밑간한 소고기를 넣고 볶는다.","imageUrl":null},{"step":5,"text":"4에 기호에 맞게 참기름과 실파를 넣는다.","imageUrl":null},{"step":6,"text":"물기를 제거한 상추에 밥 한 숟가락을 놓고 볶은 소고기, 참치, 마요네즈, 소스 순으로 얹는다.","imageUrl":null}]'::jsonb, 'http://www.foodsafetykorea.go.kr/uploadimg/20141117/20141117053804_1416213484318.jpg', 181, 24.9, 9.2, 5.2, 313),
  ('1027', '치킨 쇠고기 땅콩소스 꼬치', '반찬', '닭가슴살 30g, 쇠고기 등심 30g, 간장 3g, 카레가루 2g, 땅콩버터 3g, 참기름 0.5g, 올리브오일 2g, 설탕 1.5g, 생강다진것 1g', '["닭가슴살","쇠고기 등심","간장","카레가루","땅콩버터","참기름","올리브오일","설탕","생강다진것"]'::jsonb, ARRAY['e4027a6b-8af8-4ed1-9a86-082e9b2f4e05','1c49d1f4-5781-474d-818d-bd7002a4dc0b','f175019d-5a93-4cd4-aabc-e7e79445f15a','495b9f1e-aa3b-4506-9bb8-feb0a493901e','02c78319-0bf6-45e0-8a7b-7546e1e47ba7','0c0ade94-cfd8-4104-b44c-40e942cac482','a8ac1f24-c286-4f4c-b9fc-d9b88b5d75dc','06e6f3e7-0293-469d-a338-11a610f3e71b','c8e908a8-e613-4f21-a98e-89bb5e2d4bf9']::uuid[], '[{"step":1,"text":"닭가슴살과 소고기안심을 먹기 좋은 크기로 자른다.","imageUrl":null},{"step":2,"text":"간장, 카레가루, 땅콩버서, 참기름, 올리브오일, 설탕, 다진 생강을 섞어 소스를 만든다.","imageUrl":null},{"step":3,"text":"꼬치에 1을 번갈아 끼운다.","imageUrl":null},{"step":4,"text":"고기를 끼운 꼬치에 2의 소스를 바른다.","imageUrl":null},{"step":5,"text":"오븐을 176℃로 예열한다.","imageUrl":null},{"step":6,"text":"예열된 오븐에 소스를 바른 꼬치를 구워준다.","imageUrl":null}]'::jsonb, 'http://www.foodsafetykorea.go.kr/uploadimg/20141117/20141117053805_1416213485286.jpg', 148, 8.3, 14.4, 6.2, 536),
  ('1028', '커리향이 들어간 치킨샐러드 샌드위치', '일품', '닭가슴살 20g, 올리브오일 0.5g, 마요네즈 2g, 식빵 40g, 아몬드 3g, 건포도 2g, 카레가루 0.5g, 레몬주스 2g, 바질약간, 소금적당량, 후추적당량', '["닭가슴살","올리브오일","마요네즈","식빵","아몬드","건포도","카레가루","레몬주스","바질","소금","후추"]'::jsonb, ARRAY['e4027a6b-8af8-4ed1-9a86-082e9b2f4e05','a8ac1f24-c286-4f4c-b9fc-d9b88b5d75dc','549c7365-28e9-491f-9040-412558f93a5c','a18f6f83-06b8-473c-88b3-c2c8f2a7d0fc','52ba316f-8e7f-415f-8079-9a9d674c9adf','1c1e5578-1128-45a4-bcaf-aae79de3639e','495b9f1e-aa3b-4506-9bb8-feb0a493901e','6205dc23-e07f-4ddf-bfd8-4f17dfe4db67','ba9e5a79-cab3-4af0-942b-0b35fd745150','2cf0c12b-f248-4012-8f53-303c730a7b3d','bcb746cd-29c8-4bb2-93e4-5832b8adfa94']::uuid[], '[{"step":1,"text":"닭가슴살에 소금, 후추로 간을 한다.","imageUrl":null},{"step":2,"text":"팬에 기름을 두르고 닭가슴살을 굽는다.","imageUrl":null},{"step":3,"text":"구워 낸 닭가슴살을 다져서 볼에 담는다.","imageUrl":null},{"step":4,"text":"올리브오일, 카레가루, 레몬주스, 건포도, 아몬드, 마요네즈를 3에 넣고 섞는다.","imageUrl":null},{"step":5,"text":"식빵을 팬에 바삭하게 굽는다.","imageUrl":null},{"step":6,"text":"식빵에 치킨 샐러드를 얹은 뒤 남은 식빵으로 덮고, 사방을 잘라낸다.","imageUrl":null}]'::jsonb, 'http://www.foodsafetykorea.go.kr/uploadimg/20141117/20141117053806_1416213486379.jpg', 194, 23.3, 8.8, 7.4, 77),
  ('1030', '클럽 샌드위치', '일품', '식빵 40g, 마요네즈 2g, 삶은달걀 15g, 양상추 8g, 닭가슴살 13g, 토마토 20g, 치즈슬라이스 4g, 슬라이스햄 4g, 베이컨 4g, 소금적당량, 후추적당량', '["식빵","마요네즈","삶은달걀","양상추","닭가슴살","토마토","치즈슬라이스","슬라이스햄","베이컨","소금","후추"]'::jsonb, ARRAY['a18f6f83-06b8-473c-88b3-c2c8f2a7d0fc','549c7365-28e9-491f-9040-412558f93a5c','c7d438a6-34d6-423f-905d-446b839e2f39','1389717e-81e4-4350-96d4-d627d851aa10','e4027a6b-8af8-4ed1-9a86-082e9b2f4e05','aa597bcd-596b-4cbe-a2c4-3da0d060cb50','bd88bfed-198e-4891-9430-06660bdeaa9a','2cf0c12b-f248-4012-8f53-303c730a7b3d','bcb746cd-29c8-4bb2-93e4-5832b8adfa94']::uuid[], '[{"step":1,"text":"식빵은 앞뒤로 바삭하게 굽는다.","imageUrl":null},{"step":2,"text":"양상추는 뜯어서 찬물에 담가 두고 토마토는 얇게 슬라이스 하고 달걀도 삶아 egg slicer로 자른다.","imageUrl":null},{"step":3,"text":"닭가슴살에 소금, 후추로 간을 한 뒤 팬에서 익히고 햄과 베이컨도 살짝 굽는다.","imageUrl":null},{"step":4,"text":"식빵 한 면에 마요네즈를 바른 뒤 양상추, 베이컨, 토마토를 얹고 다시 식빵 양면에 마요네즈를 바르고 토마토 위에 얹는다.","imageUrl":null},{"step":5,"text":"그 위에 양상추, 치즈, 햄, 달걀, 닭고기를 올린 다음 나머지 빵 한 면에 마요네즈를 바른다.","imageUrl":null},{"step":6,"text":"빵 칼로 샌드위치의 사방의 테두리를 잘라내고 대각선으로 먹기 좋게 썬다.","imageUrl":null}]'::jsonb, 'http://www.foodsafetykorea.go.kr/uploadimg/20141117/20141117053808_1416213488663.jpg', 1, 1, 1, 1, 1),
  ('1031', '토마토 야채 오븐구이', '반찬', '감자 20g, 고구마 20g, 오릴브오일 2g, 홍피망 15g, 당근 12g, 후추적당량, 소금적당량, 레드어니언 12g, 토마토 25g, 돼지호박 12g, 파마산치즈 2g, 빵가루 5g, 바질약간', '["감자","고구마","오릴브오일","홍피망","당근","후추","소금","레드어니언","토마토","돼지호박","파마산치즈","빵가루","바질"]'::jsonb, ARRAY['20894da1-739d-4d52-b5fe-4943bd3492d5','4b4f0113-01cf-4dc6-ae1f-30f09e99746b','df459e6f-3515-45d5-8c9a-9d37b6249379','e38c12a7-43cb-421a-a36e-7ef0d32517fa','bcb746cd-29c8-4bb2-93e4-5832b8adfa94','2cf0c12b-f248-4012-8f53-303c730a7b3d','aa597bcd-596b-4cbe-a2c4-3da0d060cb50','4e0e50d8-ce94-4636-82f5-5bd5ac15d74c','45080597-55fa-42dc-aa65-12d7694e4b7e','ba9e5a79-cab3-4af0-942b-0b35fd745150']::uuid[], '[{"step":1,"text":"양파는 링으로 자르고 나머지 야채는 0.5cm 주사위모양으로 잘라 볼에 담는다.","imageUrl":null},{"step":2,"text":"볼에 담긴 야채에 소금을 뿌려 골고루 간이 베이도록 섞는다.","imageUrl":null},{"step":3,"text":"오븐용기에 야채를 가지런히 깔고 올리브 오일을 뿌리뒤 소금과 후추로 간을 한다.","imageUrl":null},{"step":4,"text":"그릇에 파마산 치즈와 빵가루를 넣고 잘 섞는다.","imageUrl":null},{"step":5,"text":"3의 야채 위에 4를 뿌려 덮는다.","imageUrl":null},{"step":6,"text":"180℃로 예열된 오븐에 굽는다.","imageUrl":null}]'::jsonb, 'http://www.foodsafetykorea.go.kr/uploadimg/20141117/20141117053809_1416213489835.jpg', 103, 17.4, 3.1, 2.8, 67),
  ('756', '시금치비트무침', '반찬', '주재료: 시금치(포항초) 30, 적양파 10, 비트 10 드레싱: 발사믹식초 5, 올리고당 3, 올리브유 1, 소금 0.38', '["주재료: 시금치","적양파","비트","올리고당","올리브유","소금"]'::jsonb, ARRAY['61a6a6cd-c3d6-4ba2-a033-f6e0b38bc742','524e1b82-1f81-4648-b50c-441404a06786','cc9dea71-6d38-4d4d-a688-f6ade0e7ba0d','a8ac1f24-c286-4f4c-b9fc-d9b88b5d75dc','2cf0c12b-f248-4012-8f53-303c730a7b3d']::uuid[], '[{"step":1,"text":"포항초는 깨끗이 씻어 잎을 떼어준다.","imageUrl":null},{"step":2,"text":"적양파는 얇게 슬라이스한다.","imageUrl":null},{"step":3,"text":"비트는 채 썰어 찬물에 담근다.","imageUrl":null},{"step":4,"text":"분량의 재료를 섞어 양념장을 만든다","imageUrl":null},{"step":5,"text":"포항초, 적양파, 비트의 물기를 제거한다.","imageUrl":null},{"step":6,"text":"물기를 제거한 포항초, 적양파, 비트를 소스에 버무려 낸다.","imageUrl":null}]'::jsonb, 'http://www.foodsafetykorea.go.kr/uploadimg/20141118/20141118102021_1416273621709.jpg', 38, 5.6, 2, 1.3, 152.6),
  ('757', '해초탕수', '반찬', '불린 미역(혹은 물미역) 7, 파래(생것) 10, 김 1.3, 양파 7, 유자청 15, 물 20, 다진 파 4, 다진 마늘 1, 감자전분 10, 계란 7, 콩기름 4', '["불린 미역","파래","김","양파","유자청","물","다진 파","다진 마늘","감자전분","계란","콩기름"]'::jsonb, ARRAY['09229cbc-4574-4002-b726-68c37345bbe9','61a6a6cd-c3d6-4ba2-a033-f6e0b38bc742','ff5b6cbe-7985-4ca2-94ad-5525717cddf1','94786475-832c-4f97-aab7-bf6fbbe2236b','4b410642-7bf9-45ad-9055-e7d9a34edaa1','fc6e31ce-388e-45cd-956b-b238b9134eb1','6613d1d9-80a2-4ce4-9d3d-647203197e53','c7d438a6-34d6-423f-905d-446b839e2f39','a7a59e81-de3d-4893-b56a-b2218732a25b']::uuid[], '[{"step":1,"text":"미역과 파래는 깨끗이 씻어 물기를 짜서 잘게 다지고, 김은 살짝 구워 부스러뜨린다.","imageUrl":null},{"step":2,"text":"양파와 유자청 건더기는 잘게 다진다.","imageUrl":null},{"step":3,"text":"1과 2를 합해 감자전분과 달걀을 넣어 반죽한다.","imageUrl":null},{"step":4,"text":"반죽을 동그랗게 뭉쳐 기름에 튀긴다.","imageUrl":null},{"step":5,"text":"유자청 국물에 물을 섞어 팬에 넣고 걸쭉하게 끓여 소스를 만든다.","imageUrl":null},{"step":6,"text":"해초튀김에 소스를 곁들여 낸다.","imageUrl":null}]'::jsonb, 'http://www.foodsafetykorea.go.kr/uploadimg/20141118/20141118102023_1416273623333.jpg', 128.7, 19.5, 2.1, 4.9, 132.8),
  ('759', '호두떡볶이', '반찬', '호두 15, 올리브유 4, 떡볶이 떡 80, 올리고당 20, 간장 1.5, 검정깨(볶은 것) 0.5', '["호두","올리브유","떡볶이 떡","올리고당","간장","검정깨"]'::jsonb, ARRAY['7651578f-1206-499d-a04c-15f034d4cae2','a8ac1f24-c286-4f4c-b9fc-d9b88b5d75dc','af336608-1eeb-4b10-9a3a-1df0ad140ccb','cc9dea71-6d38-4d4d-a688-f6ade0e7ba0d','f175019d-5a93-4cd4-aabc-e7e79445f15a','9e00a5b9-84e6-4cdc-afb9-0ee2bd3342fc']::uuid[], '[{"step":1,"text":"호두는 굵게 다진다.","imageUrl":null},{"step":2,"text":"다진 호두는 마른 팬에 살짝 볶는다.","imageUrl":null},{"step":3,"text":"팬에 기름을 두르고 떡이 말랑해질 때까지 볶는다.","imageUrl":null},{"step":4,"text":"떡이 익으면 올리고당과 간장을 넣어 살짝 볶는다.","imageUrl":null},{"step":5,"text":"호두를 넣어 맛이 어우러지도록 조금 더 볶는다.","imageUrl":null},{"step":6,"text":"검은깨를 뿌려내 완성한다.","imageUrl":null}]'::jsonb, 'http://www.foodsafetykorea.go.kr/uploadimg/20141118/20141118102026_1416273626065.jpg', 383.1, 57.1, 5.8, 15, 219.7),
  ('760', '죽순콩나물밥', '밥', '주재료: 쌀 90, 콩나물 30, 삶은 죽순 40, 녹차 우린 물 90 양념장: 간장 4, 고춧가루 0.5, 설탕 1, 깨소금 0.5, 다진파 2.5, 다진마늘 1.25, 청양고추 2.5, 홍고추 1.25, 맛술 3.75, 참기름 1', '["주재료: 쌀","콩나물","삶은 죽순","녹차 우린 물","고춧가루","설탕","깨소금","다진파","다진마늘","청양고추","홍고추","맛술","참기름"]'::jsonb, ARRAY['2db049b2-f39c-47ba-857f-fa02b3b0c610','84104c49-0af4-4323-a56b-b67002a422d9','06e6f3e7-0293-469d-a338-11a610f3e71b','9e00a5b9-84e6-4cdc-afb9-0ee2bd3342fc','4b410642-7bf9-45ad-9055-e7d9a34edaa1','fc6e31ce-388e-45cd-956b-b238b9134eb1','30b5d53c-d247-4f04-9b50-c0f728e65cf9','1a3a0bb7-9681-4d47-86ca-c141bcbc92d1','0c0ade94-cfd8-4104-b44c-40e942cac482']::uuid[], '[{"step":1,"text":"콩나물은 깨끗이 씻어 꼬리를 뗀다.","imageUrl":null},{"step":2,"text":"죽순은 빗살무늬를 살려 한입 크기로 얄팍하게 썬다.","imageUrl":null},{"step":3,"text":"양념장 재료를 모두 섞어 양념장을 만든다.","imageUrl":null},{"step":4,"text":"솥에 씻은 쌀을 넣고 콩나물과 죽순을 올리고 녹차 우린 물을 부어 밥을 짓는다.","imageUrl":null},{"step":5,"text":"밥이 다 되면 뜸을 들여준다.","imageUrl":null},{"step":6,"text":"밥을 푸고 양념장을 넣어 비벼 먹는다.","imageUrl":null}]'::jsonb, 'http://www.foodsafetykorea.go.kr/uploadimg/20141118/20141118102026_1416273626970.jpg', 368, 75.1, 10.1, 2.3, 226.4),
  ('761', '멍게비빔밥', '밥', '비빔밥: 쌀밥 210, 멍게살 50, 부추 10, 무순 5, 김 0.5, 참기름 4, 통깨 1.5 양념장: 고추장 5, 설탕 1, 레몬즙 3, 간 양파 3, 매실액 3', '["비빔밥: 쌀밥","멍게살","부추","무순","김","참기름","통깨","설탕","레몬즙","간 양파","매실액"]'::jsonb, ARRAY['058648c3-fd8e-476d-952f-b15dc67f1877','f09d1d41-602a-441c-a7bc-520311490ceb','09229cbc-4574-4002-b726-68c37345bbe9','0c0ade94-cfd8-4104-b44c-40e942cac482','9e00a5b9-84e6-4cdc-afb9-0ee2bd3342fc','06e6f3e7-0293-469d-a338-11a610f3e71b','6205dc23-e07f-4ddf-bfd8-4f17dfe4db67','02fd7135-0ec3-49ec-82e3-390536ab2cf5']::uuid[], '[{"step":1,"text":"멍게는 꼭지를 따고 껍질을 벗겨 한입 크기로 썬다.","imageUrl":null},{"step":2,"text":"부추는 2cm 길이로 썬다.","imageUrl":null},{"step":3,"text":"김도 부추와 같은 길이로 가늘게 채 썬다.","imageUrl":null},{"step":4,"text":"양념장 재료를 모두 섞어 양념장을 만든다.","imageUrl":null},{"step":5,"text":"손질한 멍게에 참기름을 넣어 가볍게 버무린다.","imageUrl":null},{"step":6,"text":"그릇에 밥을 담고 부추, 무순, 멍게, 김, 통깨를 올리고 양념장을 넣어 비벼 먹는다.","imageUrl":null}]'::jsonb, 'http://www.foodsafetykorea.go.kr/uploadimg/20141118/20141118102027_1416273627985.jpg', 399.5, 73.3, 9.7, 6.2, 532.8),
  ('762', '키조개샤브샤브', '국&찌개', '주재료: 키조개관자 60, 당근 10, 참나물 10, 애호박 10, 표고버섯 20, 느타리버섯 30, 팽이버섯 30, 다시마 국물 200(물 300, 다시마 1, 대파 5) 소스: 간장 4.5, 사과식초 2.5, 올리고당 3.5', '["주재료: 키조개관자","당근","참나물","애호박","표고버섯","느타리버섯","팽이버섯","다시마 국물","사과식초","올리고당"]'::jsonb, ARRAY['e38c12a7-43cb-421a-a36e-7ef0d32517fa','09065cd3-28cc-4a82-8b3e-5121054c7482','88c94a13-dc8a-4e66-ab19-08fc2ea82c77','66458b1b-c92f-43fa-8eba-e428892ce88a','7c91e298-5ace-4242-8619-cdcc80587cd7','cafedf96-06e9-46a2-a6e2-6cf6f6b15e70','a4c37075-c03b-47bb-8aed-5e907620f5d2','6c285c60-022a-4a00-b172-87df97f16a2f','cc9dea71-6d38-4d4d-a688-f6ade0e7ba0d']::uuid[], '[{"step":1,"text":"냄비에 물, 건다시마, 대파를 넣고 약불에서 30분간 맛이 우러나게 끓인다.","imageUrl":null},{"step":2,"text":"체에 걸러 다시마 국물을 만든다.","imageUrl":null},{"step":3,"text":"키조개 관자를 얇게 자른다.","imageUrl":null},{"step":4,"text":"당근은 껍질을 벗기고 채소와 버섯은 깨끗이 씻어 한입 크기로 자른다.","imageUrl":null},{"step":5,"text":"소스 재료를 냄비에 넣고 약불에서 5분간 끓여 양념장을 만든다.","imageUrl":null},{"step":6,"text":"샤브샤브 냄비에 1을 넣고 끓으면 키조개 관자, 채소, 버섯을 넣고 살짝 익혀 소스에 찍어 먹는다.","imageUrl":null}]'::jsonb, 'http://www.foodsafetykorea.go.kr/uploadimg/20141118/20141118102029_1416273629141.jpg', 85.4, 10.6, 9.3, 1, 424.8),
  ('763', '가자미쑥국', '국&찌개', '가자미 50, 모시조개 15, 쑥 20, 물 200, 된장 9, 대파 4, 들깨가루 6', '["가자미","모시조개","쑥","물","된장","대파","들깨가루"]'::jsonb, ARRAY['b6047d76-6c94-4757-b1d1-9175aea0c84a','94786475-832c-4f97-aab7-bf6fbbe2236b','392236b1-82e9-4e38-bd12-6a53b80bf463','4b410642-7bf9-45ad-9055-e7d9a34edaa1','184687ba-0cba-4fec-bb21-33fe300c2073']::uuid[], '[{"step":1,"text":"가자미는 비늘, 내장, 지느러미를 제거하고 3등분 한다.","imageUrl":null},{"step":2,"text":"물에 된장을 풀어 끓인다.","imageUrl":null},{"step":3,"text":"가자미와 모시조개를 넣고 20분 더 끓인다.","imageUrl":null},{"step":4,"text":"쑥을 넣고 5분간 팔팔 끓인다.","imageUrl":null},{"step":5,"text":"대파와 들깨가루를 넣어 살짝 끓여낸다.","imageUrl":null},{"step":6,"text":"그릇에 가자미, 쑥을 우선 담고 국믈을 곁에 부어주며 담아낸다.","imageUrl":null}]'::jsonb, 'http://www.foodsafetykorea.go.kr/uploadimg/20141118/20141118102030_1416273630141.jpg', 123.4, 3.7, 15.2, 4.9, 567.7),
  ('764', '달래바싹불고기', '반찬', '주재료: 쇠고기등심 60, 달래 5, 올리브유 5 양념장: 간장 4, 설탕 3, 다진 양파 15, 다진 마늘 2, 후추 0.01', '["주재료: 쇠고기등심","달래","올리브유","설탕","다진 양파","다진 마늘","후추"]'::jsonb, ARRAY['e4d65d59-99e9-4321-889d-5df57d5b0e18','a8ac1f24-c286-4f4c-b9fc-d9b88b5d75dc','06e6f3e7-0293-469d-a338-11a610f3e71b','61a6a6cd-c3d6-4ba2-a033-f6e0b38bc742','fc6e31ce-388e-45cd-956b-b238b9134eb1','bcb746cd-29c8-4bb2-93e4-5832b8adfa94']::uuid[], '[{"step":1,"text":"달래를 3cm 길이로 썬다.","imageUrl":null},{"step":2,"text":"양념장 재료를 모두 섞어 양념장을 만든다.","imageUrl":null},{"step":3,"text":"소고기에 달래와 양념장을 넣고 간이 배도록 잘 주무른다.","imageUrl":null},{"step":4,"text":"기름 두른 팬에 양념한 고기를 한 덩이씩 떼서 모양을 잡아준다.","imageUrl":null},{"step":5,"text":"뭉친 고기는 앞뒤로 고루 익혀낸다.","imageUrl":null},{"step":6,"text":"그릇에 담아 마무리 한다.","imageUrl":null}]'::jsonb, 'http://www.foodsafetykorea.go.kr/uploadimg/20141118/20141118102031_1416273631031.jpg', 197, 5.3, 13.4, 13.4, 237.6),
  ('765', '오리고기곰피쌈', '반찬', '주재료: 오리고기 50g, 곰피 20g, 무순 10g, 올리브유 4 소스: 오미자 액기스 1g, 고추장 6g, 설탕 2g, 식초 2.5g, 물 2.5g', '["주재료: 오리고기","곰피","무순","올리브유","고추장","설탕","식초","물"]'::jsonb, ARRAY['f09d1d41-602a-441c-a7bc-520311490ceb','a8ac1f24-c286-4f4c-b9fc-d9b88b5d75dc','84b8828b-7396-4dcb-a5d6-44e3cd5a8fdb','06e6f3e7-0293-469d-a338-11a610f3e71b','6c285c60-022a-4a00-b172-87df97f16a2f','94786475-832c-4f97-aab7-bf6fbbe2236b']::uuid[], '[{"step":1,"text":"곰피를 데쳐 찬물에 헹군다.","imageUrl":null},{"step":2,"text":"헹군 곰피는 10cm길이로 자른다.","imageUrl":null},{"step":3,"text":"오미자액기스, 고추장, 설탕, 식초, 물을 섞어 오미자 초고추장 소스를 만든다.","imageUrl":null},{"step":4,"text":"팬에 오리고기를 굽는다.","imageUrl":null},{"step":5,"text":"곰피에 오리구이와 무순을 올리고 오미자 초고추장을 발라 돌돌 말아준다.","imageUrl":null},{"step":6,"text":"그릇에 담아 완성한다.","imageUrl":null}]'::jsonb, 'http://www.foodsafetykorea.go.kr/uploadimg/20141118/20141118102033_1416273633876.jpg', 137.3, 7.8, 10.3, 7.1, 355.9),
  ('766', '바지락수제비볶음', '반찬', '주재료: 밀가루 50, 물 25, 바지락 100(바지락살 50), 양파 20, 마늘 5, 청양고추 5, 실파 5, 콩기름 4, 맛술 5, 참기름 2 양념장: 물 25, 굴소스 1.5, 간장 1, 매실액 1.5, 피쉬소스 1', '["주재료: 밀가루","물","바지락","양파","마늘","청양고추","실파","콩기름","맛술","참기름","굴소스","간장","매실액","피쉬소스"]'::jsonb, ARRAY['94786475-832c-4f97-aab7-bf6fbbe2236b','b6047d76-6c94-4757-b1d1-9175aea0c84a','61a6a6cd-c3d6-4ba2-a033-f6e0b38bc742','fc6e31ce-388e-45cd-956b-b238b9134eb1','30b5d53c-d247-4f04-9b50-c0f728e65cf9','4b410642-7bf9-45ad-9055-e7d9a34edaa1','a7a59e81-de3d-4893-b56a-b2218732a25b','1a3a0bb7-9681-4d47-86ca-c141bcbc92d1','0c0ade94-cfd8-4104-b44c-40e942cac482','d7e0d83c-010c-4b63-9ba4-fcd9af7cbac1','f175019d-5a93-4cd4-aabc-e7e79445f15a','02fd7135-0ec3-49ec-82e3-390536ab2cf5']::uuid[], '[{"step":1,"text":"밀가루에 물을 넣고 수제비 반죽을 만든다.","imageUrl":null},{"step":2,"text":"반죽을 끓는 물에 떼어 넣어 익혀 체에 받쳐둔다.","imageUrl":null},{"step":3,"text":"양파는 굵게 채 썰고 마늘은 편으로 청양고추는 어슷 썰고 실파는 송송 썬다.","imageUrl":null},{"step":4,"text":"분량의 재료를 섞어 양념장을 만든다.","imageUrl":null},{"step":5,"text":"팬에 기름을 두르고 마늘을 볶다 바지락과 맛술을 넣어 볶는다.","imageUrl":null},{"step":6,"text":"양파, 청양고추를 넣어 볶은 뒤 양념장, 수제비, 참기름을 넣어 살짝 볶는다.","imageUrl":null}]'::jsonb, 'http://www.foodsafetykorea.go.kr/uploadimg/20141118/20141118102034_1416273634751.jpg', 271.6, 43.5, 10.6, 7.1, 295.2),
  ('767', '민들레무침', '반찬', '주재료: 민들레 15, 양파 10 양념: 고춧가루 1.25, 깨소금 1, 소금 0.25, 다진 파 1.25, 다진 마늘 0.5, 매실액 4.5', '["주재료: 민들레","양파","깨소금","소금","다진 파","다진 마늘","매실액"]'::jsonb, ARRAY['61a6a6cd-c3d6-4ba2-a033-f6e0b38bc742','9e00a5b9-84e6-4cdc-afb9-0ee2bd3342fc','2cf0c12b-f248-4012-8f53-303c730a7b3d','4b410642-7bf9-45ad-9055-e7d9a34edaa1','fc6e31ce-388e-45cd-956b-b238b9134eb1','02fd7135-0ec3-49ec-82e3-390536ab2cf5']::uuid[], '[{"step":1,"text":"민들레는 흐르는 물에 씻는다.","imageUrl":null},{"step":2,"text":"깨끗이 씻은 민들레는 한입 크기로 뜯고 물기를 살짝 제거해준다.","imageUrl":null},{"step":3,"text":"양파는 얇게 채썬다.","imageUrl":null},{"step":4,"text":"양념장 재료를 모두 섞어 양념장을 만든다.","imageUrl":null},{"step":5,"text":"양파와 민들레를 볼에 담고 양념을 넣어 가볍게 무쳐낸다.","imageUrl":null},{"step":6,"text":"그릇에 담아 마무리 한다.","imageUrl":null}]'::jsonb, 'http://www.foodsafetykorea.go.kr/uploadimg/20141118/20141118102036_1416273636697.jpg', 24.9, 4, 1, 0.9, 127.9),
  ('768', '취나물들깨무침', '반찬', '참취 70g, 간장 1.5g, 소금 0.5g, 다진 파 2.25g, 다진 마늘 1g, 들기름 3g, 거피들깨가루 6g', '["참취","간장","소금","다진 파","다진 마늘","들기름","거피들깨가루"]'::jsonb, ARRAY['f175019d-5a93-4cd4-aabc-e7e79445f15a','2cf0c12b-f248-4012-8f53-303c730a7b3d','4b410642-7bf9-45ad-9055-e7d9a34edaa1','fc6e31ce-388e-45cd-956b-b238b9134eb1','f5534afd-2a26-4493-8ec1-fd680dcb3bef','184687ba-0cba-4fec-bb21-33fe300c2073']::uuid[], '[{"step":1,"text":"취나물을 끓는 물에 살짝 데친다.","imageUrl":null},{"step":2,"text":"데친 취나물은 찬물에 헹군다.","imageUrl":null},{"step":3,"text":"취나물을 가볍게 짜서 물기를 제거하고 5cm 길이로 자른다.","imageUrl":null},{"step":4,"text":"나머지 재료를 모두 섞어 양념장을 준비한다.","imageUrl":null},{"step":5,"text":"볼에 취나물을 담고 양념장을 넣어 조물조물 무쳐낸다.","imageUrl":null},{"step":6,"text":"무쳐낸 나물을 그릇에 담아 마무리한다.","imageUrl":null}]'::jsonb, 'http://www.foodsafetykorea.go.kr/uploadimg/20141118/20141118102037_1416273637730.jpg', 83.4, 5.5, 3.5, 5.7, 256.1),
  ('769', '토마토소박이', '반찬', '주재료: 토마토 70, 영양부추 5, 적양파 8 양념: 까나리액젓 2.5, 고춧가루 0.6, 소금 0.5, 통깨 1, 설탕 2', '["주재료: 토마토","영양부추","적양파","고춧가루","소금","통깨","설탕"]'::jsonb, ARRAY['058648c3-fd8e-476d-952f-b15dc67f1877','61a6a6cd-c3d6-4ba2-a033-f6e0b38bc742','84104c49-0af4-4323-a56b-b67002a422d9','2cf0c12b-f248-4012-8f53-303c730a7b3d','9e00a5b9-84e6-4cdc-afb9-0ee2bd3342fc','06e6f3e7-0293-469d-a338-11a610f3e71b']::uuid[], '[{"step":1,"text":"재료를 깨끗이 씻어낸다.","imageUrl":null},{"step":2,"text":"토마토는 끝이 떨어지지 않게 6등분 한다.","imageUrl":null},{"step":3,"text":"영양부추는 1cm 길이로 썬다.","imageUrl":null},{"step":4,"text":"적양파는 곱게 채 썬다.","imageUrl":null},{"step":5,"text":"영양부추와 적양파에 양념을 넣고 버무려 소를 만든다.","imageUrl":null},{"step":6,"text":"토마토에 소를 넣어 30분 정도 냉장고에 두었다가 먹는다.","imageUrl":null}]'::jsonb, 'http://www.foodsafetykorea.go.kr/uploadimg/20141118/20141118102038_1416273638917.jpg', 30, 5.2, 1.4, 0.7, 316.6),
  ('770', '풋마늘오징어김치', '반찬', '주재료: 풋마늘 20, 물 200, 건오징어 5 양념: 밀가루 1.25, 물 20, 소금 0.25, 고춧가루 0.6, 새우젓 0.75, 멸치액젓 0.2g, 설탕 1, 통깨 0.5, 생강즙 0.25', '["주재료: 풋마늘","물","건오징어","소금","고춧가루","새우젓","멸치액젓","설탕","통깨","생강즙"]'::jsonb, ARRAY['94786475-832c-4f97-aab7-bf6fbbe2236b','2cf0c12b-f248-4012-8f53-303c730a7b3d','84104c49-0af4-4323-a56b-b67002a422d9','8f2077de-dbd0-4372-a4c2-f987388f16b3','5fd46a51-6998-4ac9-a1fb-cab1eedf7cd9','06e6f3e7-0293-469d-a338-11a610f3e71b','9e00a5b9-84e6-4cdc-afb9-0ee2bd3342fc','c8e908a8-e613-4f21-a98e-89bb5e2d4bf9']::uuid[], '[{"step":1,"text":"풋마늘을 깨끗이 씻어 5cm 길이로 썬다.","imageUrl":null},{"step":2,"text":"물에 풋마늘을 30분 정도 담가 매운맛을 뺀다.","imageUrl":null},{"step":3,"text":"오징어를 1cm x 5cm 크기로 썬다.","imageUrl":null},{"step":4,"text":"밀가루와 물을 섞어 약불에서 풀을 쑤어 차게 식힌다.","imageUrl":null},{"step":5,"text":"풀에 나머지 양념장 재료를 모두 넣어 섞는다.","imageUrl":null},{"step":6,"text":"풋마늘과 오징어에 양념장을 넣고 버무려 즉석에서 먹거나 살짝 익혀 먹는다.","imageUrl":null}]'::jsonb, 'http://www.foodsafetykorea.go.kr/uploadimg/20141118/20141118102039_1416273639916.jpg', 39.2, 3.8, 4.7, 0.8, 220.8),
  ('771', '절편꽃말이떡', '후식', '절편 35, 거피녹두 12.5, 물 200, 다진 호두 2, 진달래꽃 2.5, 설탕 2, 소금 0.2', '["절편","거피녹두","물","다진 호두","진달래꽃","설탕","소금"]'::jsonb, ARRAY['94786475-832c-4f97-aab7-bf6fbbe2236b','7651578f-1206-499d-a04c-15f034d4cae2','06e6f3e7-0293-469d-a338-11a610f3e71b','2cf0c12b-f248-4012-8f53-303c730a7b3d']::uuid[], '[{"step":1,"text":"거피녹두를 깨끗이 씻는다.","imageUrl":null},{"step":2,"text":"씻은 녹두에 물을 넣고 푹 삶아낸다.","imageUrl":null},{"step":3,"text":"삶아 낸 녹두를 체에 밭쳐 물기를 제거하고 으깬다.","imageUrl":null},{"step":4,"text":"마른 팬에 녹두 소를 넣어 살짝 볶아 수분을 날린 다음 설탕, 소금으로 간한다.","imageUrl":null},{"step":5,"text":"절편을 5cm 길이로 잘라 밀대로 얇게 민다.","imageUrl":null},{"step":6,"text":"절편에 녹두소와 호두를 넣고 돌돌 말아 진달래를 붙인다.","imageUrl":null}]'::jsonb, 'http://www.foodsafetykorea.go.kr/uploadimg/20141118/20141118102040_1416273640697.jpg', 115.6, 20.2, 3.2, 1.7, 132.5),
  ('1034', '가지볶음', '반찬', '가지 70g, 생강 0.5g, 고추장 2g, 물엿 2g, 통깨 0.5g, 들기름 2g', '["가지","생강","고추장","물엿","통깨","들기름"]'::jsonb, ARRAY['3e12cf79-2cde-4309-9f7c-4eccce3fde28','c8e908a8-e613-4f21-a98e-89bb5e2d4bf9','84b8828b-7396-4dcb-a5d6-44e3cd5a8fdb','cc9dea71-6d38-4d4d-a688-f6ade0e7ba0d','9e00a5b9-84e6-4cdc-afb9-0ee2bd3342fc','f5534afd-2a26-4493-8ec1-fd680dcb3bef']::uuid[], '[{"step":1,"text":"가지를 깨끗하게 씻는다.","imageUrl":null},{"step":2,"text":"가지를 1x1x4cm 크기로 자른다.","imageUrl":null},{"step":3,"text":"생강을 곱게 다진다.","imageUrl":null},{"step":4,"text":"다진 생강과 고추장, 물엿, 통깨를 섞어 양념장을 만든다.","imageUrl":null},{"step":5,"text":"팬에 들기름을 넣고 센불에서 가지를 볶는다.","imageUrl":null},{"step":6,"text":"가지가 다 볶아지면 양념장을 넣고 섞일 정도로만 볶는다.","imageUrl":null}]'::jsonb, 'http://www.foodsafetykorea.go.kr/uploadimg/20141117/20141117053359_1416213239319.jpg', 37.6, 4.7, 0.9, 2.5, 68),
  ('1036', '고등어 강정', '반찬', '고등어 35g, 전분 5g, 땅콩 1g, 튀김기름 5g 생강즙 1g, 청주 2g, 소금적당량, 후춧가루 적당량간장 1g, 고추장 3g, 토마토케첩 3g, 설탕 1g, 물엿 3g, 물 5g', '["고등어","전분","땅콩","튀김기름","청주","소금","후춧가루 적당량간장","고추장","토마토케첩","설탕","물엿","물"]'::jsonb, ARRAY['f7f9c0c6-98d6-45b9-bbbe-26b57a62ee2e','6613d1d9-80a2-4ce4-9d3d-647203197e53','02c78319-0bf6-45e0-8a7b-7546e1e47ba7','a7a59e81-de3d-4893-b56a-b2218732a25b','1a3a0bb7-9681-4d47-86ca-c141bcbc92d1','2cf0c12b-f248-4012-8f53-303c730a7b3d','84b8828b-7396-4dcb-a5d6-44e3cd5a8fdb','0136fc6a-3a80-4f4c-8057-10bbf34ea572','06e6f3e7-0293-469d-a338-11a610f3e71b','cc9dea71-6d38-4d4d-a688-f6ade0e7ba0d','94786475-832c-4f97-aab7-bf6fbbe2236b']::uuid[], '[{"step":1,"text":"고등어는 머리를 자른 뒤 내장을 빼고 잘 씻어 물기를 제거한다.","imageUrl":null},{"step":2,"text":"1의 살만 포를 떠서 한입 크기로 자른 뒤 청주, 생강즙, 소금, 후춧가루를 뿌려 밑간 한다.","imageUrl":null},{"step":3,"text":"전분을 앞, 뒤로 묻혀 170℃ 튀김 기름에 2번 바삭하게 튀긴다.","imageUrl":null},{"step":4,"text":"땅콩은 껍질을 벗긴 뒤 비닐봉지에 담아 밀대로 찧어 굵게 다진다.","imageUrl":null},{"step":5,"text":"냄비에 간장, 고추장, 설탕, 물엿을 넣고 끓여 조림장을 만든다.","imageUrl":null},{"step":6,"text":"조림장이 반으로 졸아들면 튀긴 고등어와 땅콩을 넣고 살살 뒤집어가며 윤기나게 버무린다.","imageUrl":null}]'::jsonb, 'http://www.foodsafetykorea.go.kr/uploadimg/20141117/20141117053815_1416213495241.jpg', 154.6, 10.1, 7.8, 9.1, 207),
  ('1037', '꽃게볶음', '반찬', '꽃게 70g, 청주 2g, 전분 3g, 실파 5g, 참기름 2g, 건고추 3g, 마늘다진것 3g, 생강다진것 2g, 소금적당량, 후춧가루적당량 간장 2g, 청주 2g, 설탕 3g, 물 3g', '["꽃게","청주","전분","실파","참기름","건고추","마늘다진것","생강다진것","소금","후춧가루적당량 간장","설탕","물"]'::jsonb, ARRAY['0c2a6773-2dcd-4ed5-a02c-4a52b1bdeab4','1a3a0bb7-9681-4d47-86ca-c141bcbc92d1','6613d1d9-80a2-4ce4-9d3d-647203197e53','4b410642-7bf9-45ad-9055-e7d9a34edaa1','0c0ade94-cfd8-4104-b44c-40e942cac482','fc6e31ce-388e-45cd-956b-b238b9134eb1','c8e908a8-e613-4f21-a98e-89bb5e2d4bf9','2cf0c12b-f248-4012-8f53-303c730a7b3d','06e6f3e7-0293-469d-a338-11a610f3e71b','94786475-832c-4f97-aab7-bf6fbbe2236b']::uuid[], '[{"step":1,"text":"솔을 이용해 게를 깨끗이 씻어 물기를 뺀 뒤 등딱지를 떼고 먹기 좋은 크기로 토막내 소금, 후춧가루, 청주로 밑간 한다.","imageUrl":null},{"step":2,"text":"전분을 묻힌 뒤 찜통에 찐다.","imageUrl":null},{"step":3,"text":"마늘, 생강은 얇게 편썰고 실파는 3cm 길이로 썰고 건 고추는 어슷하게 썬다.","imageUrl":null},{"step":4,"text":"팬에 기름을 두르고 마늘, 생강, 건고추를 넣고 볶는다.","imageUrl":null},{"step":5,"text":"매콤한 향이 나면 양념장을 넣고 살짝 볶으면서 찐 게를 넣어 맛이 베이도록 뒤적이며 볶는다.","imageUrl":null},{"step":6,"text":"마지막에 실파를 넣고 참기름으로 향을 낸다.","imageUrl":null}]'::jsonb, 'http://www.foodsafetykorea.go.kr/uploadimg/20141117/20141117053816_1416213496599.jpg', 109, 10.1, 10.3, 2.9, 317),
  ('1038', '다시마칩', '후식', '다시마 25g, 꿀 7g, 참께 4g, 오트밀 4g', '["다시마","꿀","참께","오트밀"]'::jsonb, ARRAY['84032a7e-ec18-44d5-ab30-c7b960ca5ca9','286d1783-cd34-4aae-ac8b-006529ec8bc5']::uuid[], '[{"step":1,"text":"다시마를 젖은 행주로 깨끗하게 닦는다.","imageUrl":null},{"step":2,"text":"다시마를 4x5cm 크기로 자른다.","imageUrl":null},{"step":3,"text":"자른 다시마를 파이팬에 올린다.","imageUrl":null},{"step":4,"text":"예열된 오븐에서 다시마를 굽는다.","imageUrl":null},{"step":5,"text":"구운 다시마에 꿀을 묻힌다.","imageUrl":null},{"step":6,"text":"참깨나 오트밀을 묻힌다.","imageUrl":null}]'::jsonb, 'http://www.foodsafetykorea.go.kr/uploadimg/20141117/20141117053817_1416213497711.jpg', 61, 10.3, 1.6, 2.5, 139),
  ('1039', '브로콜리 쇠고기 볶음', '반찬', '브로콜리 70g, 쇠고기안심 30g, 물전분 6g, 당근 10g, 마늘다진것 3g, 간장 3g, 생강 3g, 설탕 3g, 식물성기름 2g, 소금적당량', '["브로콜리","쇠고기안심","물전분","당근","마늘다진것","간장","생강","설탕","식물성기름","소금"]'::jsonb, ARRAY['9bf64924-ce53-42bb-849e-7294416e95d6','6613d1d9-80a2-4ce4-9d3d-647203197e53','e38c12a7-43cb-421a-a36e-7ef0d32517fa','fc6e31ce-388e-45cd-956b-b238b9134eb1','f175019d-5a93-4cd4-aabc-e7e79445f15a','c8e908a8-e613-4f21-a98e-89bb5e2d4bf9','06e6f3e7-0293-469d-a338-11a610f3e71b','2cf0c12b-f248-4012-8f53-303c730a7b3d']::uuid[], '[{"step":1,"text":"브로콜리는 소금물에 담궜다가 씻는다.","imageUrl":null},{"step":2,"text":"브로콜리를 작은 송이로 자른 뒤 기름, 소금을 넣은 물에 데쳐 찬물에 헹군다.","imageUrl":null},{"step":3,"text":"생강과 당근, 마늘, 소고기를 얇게 슬라이스 한다.","imageUrl":null},{"step":4,"text":"소고기를 밑간 한 뒤 10분 정도 재웠다가 기름을 두르고 살짝 익힌다.","imageUrl":null},{"step":5,"text":"마늘, 생강, 당근, 익혀둔 소고기를 팬에 넣고 브로콜리를 넣어 볶는다.","imageUrl":null},{"step":6,"text":"물 전분을 이용해 소스의 농도를 맞춘다.","imageUrl":null}]'::jsonb, 'http://www.foodsafetykorea.go.kr/uploadimg/20141117/20141117053818_1416213498790.jpg', 124, 13.9, 1.2, 4.1, 300),
  ('1040', '새우살을 채운 두부 스프(미네스트로네)', '일품', '새우 35g, 두부 50g, 당근 10g, 돼지호박 10g, 참기름 1g, 생강 1g, 양파 10g, 마늘다진것 1g, 닭육수 70g, 굴소스 3g, 간장 2g, 소금적당량달걀흰자 5g, 전분 2g, 소금 적당량', '["새우","두부","당근","돼지호박","참기름","생강","양파","마늘다진것","닭육수","굴소스","간장","소금적당량달걀흰자","전분","소금"]'::jsonb, ARRAY['6f10b4ad-53a2-4a07-ba89-19a6b074373d','4566cac5-9166-4c0d-906a-bfc7360f8f5b','e38c12a7-43cb-421a-a36e-7ef0d32517fa','0c0ade94-cfd8-4104-b44c-40e942cac482','c8e908a8-e613-4f21-a98e-89bb5e2d4bf9','61a6a6cd-c3d6-4ba2-a033-f6e0b38bc742','fc6e31ce-388e-45cd-956b-b238b9134eb1','a4c37075-c03b-47bb-8aed-5e907620f5d2','d7e0d83c-010c-4b63-9ba4-fcd9af7cbac1','f175019d-5a93-4cd4-aabc-e7e79445f15a','6613d1d9-80a2-4ce4-9d3d-647203197e53','2cf0c12b-f248-4012-8f53-303c730a7b3d']::uuid[], '[{"step":1,"text":"새우살을 다져서 양념한다.","imageUrl":null},{"step":2,"text":"두부는 4x3cm로 썰어 한 쪽 면은 속을 파내고 간이 된 새우살을 채운 뒤 전분을 묻혀 지진다.","imageUrl":null},{"step":3,"text":"당근, 양파, 돼지호박은 1.5x1.5x0.2cm 크기로 썬다.","imageUrl":null},{"step":4,"text":"팬에 참기름을 두르고 3을 타지 않도록 잘 볶은 뒤 생강, 다진 마늘을 넣고 볶다가 닭육수를 넣어 끓인다.","imageUrl":null},{"step":5,"text":"육수에 간장과 굴소스로 간을 맞춘다.","imageUrl":null},{"step":6,"text":"그릇에 지져낸 새우살을 채운 두부를 넣고 끓인 미네스트로네를 담는다.","imageUrl":null}]'::jsonb, 'http://www.foodsafetykorea.go.kr/uploadimg/20141117/20141117053819_1416213499570.jpg', 117, 5.9, 13.8, 4.6, 361),
  ('1042', '시저 샐러드', '반찬', '상추/로메인 60g, 마늘다진것 3g, 앤쵸비 3g, 소금 적당량, 후추 적당량, 달걀노른자 5g, 레몬주스 3g, 올리브오일 1g, 파마산 치즈 5g, 도미살 30g, 밀가루 8g, 달걀물 5g, 빵가루 4g파슬리다진것 2g, 오레가노다진것 1g, 식빵 20g, 소금적당량, 후추 적당량', '["상추/로메인","마늘다진것","앤쵸비","소금","후추","달걀노른자","레몬주스","올리브오일","파마산 치즈","도미살","밀가루","달걀물","빵가루","오레가노다진것","식빵"]'::jsonb, ARRAY['fc6e31ce-388e-45cd-956b-b238b9134eb1','2cf0c12b-f248-4012-8f53-303c730a7b3d','bcb746cd-29c8-4bb2-93e4-5832b8adfa94','c7d438a6-34d6-423f-905d-446b839e2f39','6205dc23-e07f-4ddf-bfd8-4f17dfe4db67','a8ac1f24-c286-4f4c-b9fc-d9b88b5d75dc','4e0e50d8-ce94-4636-82f5-5bd5ac15d74c','aab3b0b9-d346-4697-a1c8-1b1530153788','45080597-55fa-42dc-aa65-12d7694e4b7e','cdbae946-7ca4-4f8d-8a3c-5bb295961ad6','a18f6f83-06b8-473c-88b3-c2c8f2a7d0fc']::uuid[], '[{"step":1,"text":"상추 잎을 떼내어 잘 씻은 다음 물기를 제거하고 적당한 크기로 잘라 냉장고에서 보관한다.","imageUrl":null},{"step":2,"text":"크루통을 만들고 서빙하기 전까지 따로 보관한다.","imageUrl":null},{"step":3,"text":"마늘, 앤초비, 소금, 후추를 넣고 페이스트를 만든 뒤 달걀 노른자, 레몬주스를 넣고 섞는다.","imageUrl":null},{"step":4,"text":"3에 올리브오일을 넣어 진한 농도가 나도록 한 뒤 파마산치즈를 넣고 상추를 넣어 잘 섞는다.","imageUrl":null},{"step":5,"text":"도미살을 손가락 길이로 썰어 소금, 후추로 간을 하고 밀가루, 달걀물, 빵가루 순으로 묻혀 170℃ 정도의 기름에서 튀긴다.","imageUrl":null},{"step":6,"text":"차가운 접시에 4, 5를 담고 크루통을 뿌린다.","imageUrl":null}]'::jsonb, 'http://www.foodsafetykorea.go.kr/uploadimg/20141117/20141117053821_1416213501772.jpg', 213, 24.5, 14.5, 6.4, 220),
  ('1043', '연두부 무순 냉국', '국&찌개', '연두부 75g, 무순 10g, 대파 5g, 청고추 3g, 홍고추 3g, 쑥갓 2g, 통깨 1g, 소금적당량 다시마육수 90g, 간장 4g, 맛술 2g, 식초 2g, 설탕 3g', '["연두부","무순","대파","청고추","홍고추","쑥갓","통깨","소금적당량 다시마육수","간장","맛술","식초","설탕"]'::jsonb, ARRAY['4566cac5-9166-4c0d-906a-bfc7360f8f5b','f09d1d41-602a-441c-a7bc-520311490ceb','4b410642-7bf9-45ad-9055-e7d9a34edaa1','30b5d53c-d247-4f04-9b50-c0f728e65cf9','10ccd1c9-12d7-4075-b2cc-bfc87ce891b6','9e00a5b9-84e6-4cdc-afb9-0ee2bd3342fc','f175019d-5a93-4cd4-aabc-e7e79445f15a','1a3a0bb7-9681-4d47-86ca-c141bcbc92d1','6c285c60-022a-4a00-b172-87df97f16a2f','06e6f3e7-0293-469d-a338-11a610f3e71b']::uuid[], '[{"step":1,"text":"무순의 잡티를 제거한 뒤 물에 흔들어 씻어 물기를 뺀다.","imageUrl":null},{"step":2,"text":"연두부는 적당한 크기로 나눈다.","imageUrl":null},{"step":3,"text":"다시마 육수에 분량의 재료를 섞어 냉국 국물을 만든 뒤 냉장고에 넣어 차갑게 만든다.","imageUrl":null},{"step":4,"text":"청, 홍고추, 대파는 2cm 길이로 곱게 채 썬다.","imageUrl":null},{"step":5,"text":"냉국 그릇에 2의 연두부를 담고 무순, 채썬 대파, 청, 홍고추를 가지런히 올린다.","imageUrl":null},{"step":6,"text":"5의 연두부에 차게 준비한 냉국 국물을 붓고 쑥갓을 얹은 뒤 통깨를 뿌린다.","imageUrl":null}]'::jsonb, 'http://www.foodsafetykorea.go.kr/uploadimg/20141117/20141117053823_1416213503163.jpg', 71, 6.3, 6, 3, 223),
  ('1045', '차가운 당근 수프', '일품', '당근 80g, 버터 2g, 양파다진것 10g, 생강다진것 1g, 마늘다진것 2g, 야채육수 50g, 오렌지주스 20g, 생크림 5g, 당근주스 30g, 소금적당량', '["당근","버터","양파다진것","생강다진것","마늘다진것","야채육수","오렌지주스","생크림","당근주스","소금"]'::jsonb, ARRAY['e38c12a7-43cb-421a-a36e-7ef0d32517fa','7aabd532-361f-4240-aa33-6bfa1be4bc4e','61a6a6cd-c3d6-4ba2-a033-f6e0b38bc742','c8e908a8-e613-4f21-a98e-89bb5e2d4bf9','fc6e31ce-388e-45cd-956b-b238b9134eb1','19eb37dc-2b1c-4e89-a931-31a38ae60561','af187077-b7f6-4b0e-9e99-f844f6359ac2','2cf0c12b-f248-4012-8f53-303c730a7b3d']::uuid[], '[{"step":1,"text":"버터를 녹인 냄비에 양파, 생강, 마늘 다진 것을 넣고 양파가 반투명해 질 때까지 볶는다.","imageUrl":null},{"step":2,"text":"1에 얇게 썬 당근을 넣고 볶는다.","imageUrl":null},{"step":3,"text":"2에 야채육수, 오렌지주스를 넣고 당근이 익을 때까지 끓인다.","imageUrl":null},{"step":4,"text":"믹서에 3을 넣고 갈아준 뒤 차갑게 한다.","imageUrl":null},{"step":5,"text":"제공하기 직전에 크림을 넣어 섞은 뒤 당근주스를 넣는다.","imageUrl":null},{"step":6,"text":"소금, 후추로 마지막 간을 하고 차가운 볼에 담는다.","imageUrl":null}]'::jsonb, 'http://www.foodsafetykorea.go.kr/uploadimg/20141117/20141117053825_1416213505303.jpg', 84, 13.2, 2.3, 3.3, 57),
  ('1046', '태국식 불고기 샐러드', '반찬', '쇠고기 30g, 애호박 20g, 토마토 25g, 가지 15g, 양파 8g, 새송이버섯 15g, 그린 샐러드적당량 풋고추 3g, 홍고추 3g, 마늘 1g, 고춧가루 1g, 레몬주스 3g, 타바스코 1g올리브오일 1g, 로즈마리 1g, 민트 1g, 카레가루 2g', '["쇠고기","애호박","토마토","가지","양파","새송이버섯","그린 샐러드적당량 풋고추","홍고추","마늘","고춧가루","레몬주스","타바스코","로즈마리","민트","카레가루"]'::jsonb, ARRAY['1c49d1f4-5781-474d-818d-bd7002a4dc0b','88c94a13-dc8a-4e66-ab19-08fc2ea82c77','aa597bcd-596b-4cbe-a2c4-3da0d060cb50','3e12cf79-2cde-4309-9f7c-4eccce3fde28','61a6a6cd-c3d6-4ba2-a033-f6e0b38bc742','3f94371a-728f-49ae-8ea9-1a1e87b68048','30b5d53c-d247-4f04-9b50-c0f728e65cf9','fc6e31ce-388e-45cd-956b-b238b9134eb1','84104c49-0af4-4323-a56b-b67002a422d9','6205dc23-e07f-4ddf-bfd8-4f17dfe4db67','722e0bf6-fae4-4bb8-bb95-f7b407b085d7','eb4621c9-6ade-40ba-966c-32edd1754669','495b9f1e-aa3b-4506-9bb8-feb0a493901e']::uuid[], '[{"step":1,"text":"소고기는 불고기용으로 손질하여 소금, 후추로 밑간한다.","imageUrl":null},{"step":2,"text":"애호박, 토마토, 가지, 양파, 새송이버섯을 채 썬 뒤 볶는다.","imageUrl":null},{"step":3,"text":"밑간해 둔 소고기를 굽는다.","imageUrl":null},{"step":4,"text":"접시에 밥을 깔고 그 위에 그린샐러드를 올린 뒤 익혀놓은 고기와 볶아놓은 야채들을 올린다.","imageUrl":null},{"step":5,"text":"마지막으로 드래싱을 뿌린다.","imageUrl":null}]'::jsonb, 'http://www.foodsafetykorea.go.kr/uploadimg/20141117/20141117053826_1416213506192.jpg', 89, 8.8, 8.3, 3.1, 242),
  ('1047', '팽이버섯 야채볶음', '반찬', '팽이버섯 70g, 청경채 50g, 참기름 2g, 식용유 2g, 물전분 6g, 소금 적당량', '["팽이버섯","청경채","참기름","식용유","물전분","소금"]'::jsonb, ARRAY['cafedf96-06e9-46a2-a6e2-6cf6f6b15e70','7ac59c14-e767-4f32-a2e5-d558c1a29dfb','0c0ade94-cfd8-4104-b44c-40e942cac482','a7a59e81-de3d-4893-b56a-b2218732a25b','6613d1d9-80a2-4ce4-9d3d-647203197e53','2cf0c12b-f248-4012-8f53-303c730a7b3d']::uuid[], '[{"step":1,"text":"팽이버섯은 밑동을 제거하고 4cm 길이로 자른다.","imageUrl":null},{"step":2,"text":"청경채는 겉잎을 떼어낸 뒤 반으로 가른 뒤 팽이버섯과 같은 길이로 자른다.","imageUrl":null},{"step":3,"text":"썰어 놓은 팽이버섯과 청경채를 끓는 물에 데친다.","imageUrl":null},{"step":4,"text":"기름을 두른 팬에 팽이버섯과 청경채를 볶는다.","imageUrl":null},{"step":5,"text":"물 전분을 넣어 농도를 맞춘다.","imageUrl":null},{"step":6,"text":"참기름을 뿌려 완성한다.","imageUrl":null}]'::jsonb, 'http://www.foodsafetykorea.go.kr/uploadimg/20141117/20141117053827_1416213507603.jpg', 83, 10.9, 2.6, 4.4, 14),
  ('772', '딸기연두부쉐이크', '후식', '딸기 100g, 연두부 50g, 바나나 50g, 올리고당 10g', '["딸기","연두부","바나나","올리고당"]'::jsonb, ARRAY['60a7c3e6-e703-4fb0-b5d9-0119a5deab83','4566cac5-9166-4c0d-906a-bfc7360f8f5b','1a4b39f8-b581-46dc-bd7e-289cd6160711','cc9dea71-6d38-4d4d-a688-f6ade0e7ba0d']::uuid[], '[{"step":1,"text":"딸기를 깨끗이 씻는다.","imageUrl":null},{"step":2,"text":"딸기의 꼭지를 뗀다.","imageUrl":null},{"step":3,"text":"딸기, 바나나를 잘게 썰어 믹서에 넣는다.","imageUrl":null},{"step":4,"text":"연두부를 믹서에 넣고 함께 간다.","imageUrl":null},{"step":5,"text":"올리고당을 넣는다.","imageUrl":null},{"step":6,"text":"컵에 담아 완성한다.","imageUrl":null}]'::jsonb, 'http://www.foodsafetykorea.go.kr/uploadimg/20141118/20141118102045_1416273645494.jpg', 121, 25.3, 4, 1.5, 5.5),
  ('774', '봄주먹밥', '밥', ' 1인분 봄동 10g, 깻잎 6g, 낙지다리 6g, 참기름 3g 두릎 8g, 올리브유 4g, 미나리 3g 주먹밥 데친꼬막살 12g, 올리브유 4g, 밥 100g, 참깨 3g 두부강된장 참기름 10g, 다진양파 14g, 다진당근 14g, 다진애호박 14g, 물 150g, 된장 14g, 고춧가루 4g, 다진마늘 4g, 붉은고추 4g', '["깻잎","낙지다리","참기름","올리브유","미나리","밥","참깨","다진양파","다진당근","다진애호박","물","된장","고춧가루","다진마늘","붉은고추"]'::jsonb, ARRAY['3c38eb1c-6ef4-4bb8-82be-74f679ce9e91','0c0ade94-cfd8-4104-b44c-40e942cac482','a8ac1f24-c286-4f4c-b9fc-d9b88b5d75dc','dc7b2b73-74de-4fb8-9274-a5967ca444f9','ecb35816-34ae-4c4c-867a-e3f84db92755','9e00a5b9-84e6-4cdc-afb9-0ee2bd3342fc','61a6a6cd-c3d6-4ba2-a033-f6e0b38bc742','e38c12a7-43cb-421a-a36e-7ef0d32517fa','88c94a13-dc8a-4e66-ab19-08fc2ea82c77','94786475-832c-4f97-aab7-bf6fbbe2236b','392236b1-82e9-4e38-bd12-6a53b80bf463','84104c49-0af4-4323-a56b-b67002a422d9','fc6e31ce-388e-45cd-956b-b238b9134eb1','30b5d53c-d247-4f04-9b50-c0f728e65cf9']::uuid[], '[{"step":1,"text":"봄동과 깻잎은 데친 뒤 체에 밭쳐 물기를 제거한다.","imageUrl":null},{"step":2,"text":"데친 꼬막살은 물기를 제거하고 다져 올리브유로 양념한 밥에 참께와 함께 버무린 후 한입 크기로 주먹밥을 만든다.","imageUrl":null},{"step":3,"text":"낙지 다리는 데처 찬물에 담가 식힌 뒤 참기름(3g)에 양념하고, 두릅은 데쳐 물기를 제거한 뒤 올리브유로 양념한다.","imageUrl":null},{"step":4,"text":"봄동에 꼬막밥을 넣고 만 뒤 껫잎으로 싸고 데친 미나리로 묶어 봄주먹밥을 만든다.","imageUrl":null},{"step":5,"text":"냄비에 참기름을 두르고 양파, 당근, 애호박을 볶은 뒤 물, 된장, 고춧가루, 다진마늘, 붉은고추, 청양고추, 두부를 넣고 조려 두부강된장을 만든다.","imageUrl":null},{"step":6,"text":"봄주먹밥에 낙지와 두릅, 두부강된장을 곁들여 마무리한다.","imageUrl":null}]'::jsonb, 'http://www.foodsafetykorea.go.kr/uploadimg/20160318/20160318051200_1458288720482.png', 252.4, 19.63, 4.29, 2.12, 118.1),
  ('775', '구운 주먹밥', '밥', '현미(100g), 톳(30g), 생김(5g), 달걀(50g), 밥 밑간 참기름(4g), 참깨(2g), 톳 무침양념 설탕(2g), 식초(2g)', '["현미","톳","생김","달걀","밥 밑간 참기름","참깨","톳 무침양념 설탕","식초"]'::jsonb, ARRAY['a5bc0b46-0192-496a-b429-d2cb90b2bca9','f3f07b4b-1a27-4a6d-be6d-09e58352e063','c7d438a6-34d6-423f-905d-446b839e2f39','9e00a5b9-84e6-4cdc-afb9-0ee2bd3342fc','6c285c60-022a-4a00-b172-87df97f16a2f']::uuid[], '[{"step":1,"text":"현미로 밥을 지은 뒤 밥 밑간을 넣고 섞는다.","imageUrl":null},{"step":2,"text":"톳에 톳 무침양념을 넣고 버무린다.","imageUrl":null},{"step":3,"text":"밥에 톳을 넣고 버무린다.","imageUrl":null},{"step":4,"text":"밥을 먹기 좋은 크기로 둥글게 뭉친 뒤 부순 생김을 골고루 묻힌다.","imageUrl":null},{"step":5,"text":"주먹밥을 달걀물을 입힌다.","imageUrl":null},{"step":6,"text":"팬에 구워 마무리한다.","imageUrl":null}]'::jsonb, 'http://www.foodsafetykorea.go.kr/uploadimg/20160503/20160503104705_1462240025010.jpg', 335.1, 35.43, 5.79, 6.84, 79.4),
  ('776', '깻잎장아찌롤', '밥', '쌀(200g), 깻잎장아찌(30g), 김(5g), 새싹(20g), 밥 밑간 참기름(5g), 참깨(3g), 허브타르타르드레싱 양파(20g), 피클(20g), 삶은달걀(60g), 마요네즈(20g), 머스터드소스 설탕(3g), 물(5g), 머스터드조스(1.5g)', '["쌀","깻잎장아찌","김","새싹","밥 밑간 참기름","참깨","허브타르타르드레싱 양파","피클","삶은달걀","마요네즈","머스터드소스 설탕","물","머스터드조스"]'::jsonb, ARRAY['a5bc0b46-0192-496a-b429-d2cb90b2bca9','09229cbc-4574-4002-b726-68c37345bbe9','bc0ebb76-798a-40fe-be99-557ca2b9a9b4','9e00a5b9-84e6-4cdc-afb9-0ee2bd3342fc','c7d438a6-34d6-423f-905d-446b839e2f39','549c7365-28e9-491f-9040-412558f93a5c','94786475-832c-4f97-aab7-bf6fbbe2236b']::uuid[], '[{"step":1,"text":"쌀을 씻어 밥을 지은 뒤 밥 밑간을 한다.","imageUrl":null},{"step":2,"text":"양파, 피클, 삶은 달걀은 다진 뒤 마요네즈에 섞어 허브타르타르드레싱을 만든다.","imageUrl":null},{"step":3,"text":"김 위에 밥을 펴고 허브타르타르드레싱을 위에 올리 후 만다.","imageUrl":null},{"step":4,"text":"깻잎장아찌를 바닥에 깔고 말아놓은 롤을 올린 후 한 번 더 만다.","imageUrl":null},{"step":5,"text":"머스트드소스를 만든다.","imageUrl":null},{"step":6,"text":"한입 크기로 롤을 썬 뒤 새싹과 소스를 곁들여 마무리한다.","imageUrl":null}]'::jsonb, 'http://www.foodsafetykorea.go.kr/uploadimg/20160603/20160603011759_1464927479016.jpg', 375.2, 18.4, 2.6, 3.4, 750.7),
  ('777', '롤 삼계탕', '국&찌개', ' 마 30g(1/3개), 대추20g(10개), 은행35g(25개), 단호박 40g(1/8개), 아스파라거스 15g(1/3개), 영콘 20g(1개), 마늘 10g(2개), 쌀 200g(1컴)
, 닭 550g(1마리), 파 15g(1큰술), 마늘 15(3개)', '["마","대추","은행","단호박","아스파라거스","영콘","마늘","쌀","닭","파"]'::jsonb, ARRAY['a988ffbb-92c3-4c68-8cea-a2f10c329015','b371c5d2-f12b-47ee-9a87-26efd09db09d','9c201731-bb59-4929-8996-f11933f4f27a','98d652af-a6d6-440c-9653-e22fc5d47d88','a8462d27-4ef1-4919-ae9b-10c8f8b9545f','fc6e31ce-388e-45cd-956b-b238b9134eb1','a5bc0b46-0192-496a-b429-d2cb90b2bca9','4b410642-7bf9-45ad-9055-e7d9a34edaa1']::uuid[], '[{"step":1,"text":"닭은 살을 발라낸다.","imageUrl":null},{"step":2,"text":"남은 뼈는 파, 마늘을 넣고 육수를 만든다.","imageUrl":null},{"step":3,"text":"마와 단호박은 1x1x5cm로 썬다.","imageUrl":null},{"step":4,"text":"마늘, 아스파라거스, 영콘은 굽는다.","imageUrl":null},{"step":5,"text":"닭에 마, 대추, 쌀, 단호박, 은행을 넣고 랩으로 감싸 만다.","imageUrl":null},{"step":6,"text":"곁들일 단호박과 찜통에 찐다.","imageUrl":null}]'::jsonb, 'http://www.foodsafetykorea.go.kr/uploadimg/20160708/20160708060607_1467968767734.jpg', 103.4, 4.3, 11.9, 4.3, 50.2),
  ('779', '효종갱(曉鍾羹)', '국&찌개', ': 배추(20g), 무(10g), 느타리버섯(20g),육수: 쇠고기(양지 50g, 갈비 50g), 양파(40g), 마늘(10g), 물(300g),양념: 저염간장(10g)', '[": 배추","무","느타리버섯","육수: 쇠고기","양파","마늘","물","양념: 저염간장"]'::jsonb, ARRAY['f80c9a7d-1510-44e2-a82b-28b9f684e191','7c91e298-5ace-4242-8619-cdcc80587cd7','61a6a6cd-c3d6-4ba2-a033-f6e0b38bc742','fc6e31ce-388e-45cd-956b-b238b9134eb1','94786475-832c-4f97-aab7-bf6fbbe2236b']::uuid[], '[{"step":1,"text":"소고기는 핏물을 제거한 뒤 양파, 마늘을 넣고 물(300g)을 부어 1시간 이상 끓인 뒤 면포에 걸러 육수를 만든다.","imageUrl":null},{"step":2,"text":"삶은 소고기는 건져내 결 반대 방향으로 썬다.","imageUrl":null},{"step":3,"text":"배추, 무, 느타리버섯, 표고버섯은 먹기 좋은 크기로 썬다.","imageUrl":null},{"step":4,"text":"전복은 깨끗이 손질한다.","imageUrl":null},{"step":5,"text":"육수를 끓인 뒤 끓어오르면 무를 넣어 반투명해지면 배추, 버섯, 전복을 넣는다.","imageUrl":null},{"step":6,"text":"전복이 익으면 소고기를 넣고 저염간장으로 간을 해 마무리한다.","imageUrl":null}]'::jsonb, 'http://www.foodsafetykorea.go.kr/uploadimg/20160913/20160913012533_1473740733647.jpg', 186.1, 0.99, 4.95, 1.69, 220.6),
  ('781', '갯벌의 여왕 모시조개의 달콤한 유혹', '반찬', '바지락(모시조개( 200g(30개), 양파 15g(2*4cm), 마늘 10g(2쪽), 마른 홍고추 1g(1/5개), 올리브유 15g(1큰술), 호이트와인 15ml(1큰술), 쳥양고추 3g(1/3개), 저염치즈 10g(2작은술), 후추 약간, 바질 약간', '["바지락","양파","마늘","마른 홍고추","올리브유","호이트와인","쳥양고추","저염치즈","후추","바질"]'::jsonb, ARRAY['b6047d76-6c94-4757-b1d1-9175aea0c84a','61a6a6cd-c3d6-4ba2-a033-f6e0b38bc742','fc6e31ce-388e-45cd-956b-b238b9134eb1','a8ac1f24-c286-4f4c-b9fc-d9b88b5d75dc','4e0e50d8-ce94-4636-82f5-5bd5ac15d74c','bcb746cd-29c8-4bb2-93e4-5832b8adfa94','ba9e5a79-cab3-4af0-942b-0b35fd745150']::uuid[], '[{"step":1,"text":"양파는 잘게 썰고 청양고추는 어슷썰기를 한다.","imageUrl":null},{"step":2,"text":"마늘은 편으로 썰고 마른 홍고추도 둥글게 썰어 준비한다.","imageUrl":null},{"step":3,"text":"조개는 흐르는 물에 여러 번 씻어 해감을 시킨 후 물기를 제거한다.","imageUrl":null},{"step":4,"text":"달궈진 팬에 올리브오일을 두르고 마늘, 마른홍고추, 양파를 넣어 볶아 향을 낸 후, 센불로 불을 키우고 모시조개를 넣는다.","imageUrl":null},{"step":5,"text":"조개가 입을 벌리면 바질과 화이트와인을 넣어 잡내를 없앤다.","imageUrl":null},{"step":6,"text":"한소끔 끓여낸 후 붕간 불로 줄이고 저염치즈, 청양고추, 후추를 넣어 칼칼한 맛을 낸다.","imageUrl":null}]'::jsonb, 'http://www.foodsafetykorea.go.kr/uploadimg/20161205/20161205092004_1480940404421.jpg', 155, 7, 11, 9, 760),
  ('782', '고구마 타락죽', '밥', '고구마 20g, 양송이버섯 15g, 양파 10g, 느타리버섯 7g, 현미(불린것) 30g, 저지방우유 130g, 식용유 20g, 물 100g', '["고구마","양송이버섯","양파","느타리버섯","현미","저지방우유","식용유","물"]'::jsonb, ARRAY['4b4f0113-01cf-4dc6-ae1f-30f09e99746b','48a4fd5a-e4f6-467b-9e3f-445334e0ee04','61a6a6cd-c3d6-4ba2-a033-f6e0b38bc742','7c91e298-5ace-4242-8619-cdcc80587cd7','a5bc0b46-0192-496a-b429-d2cb90b2bca9','a7a59e81-de3d-4893-b56a-b2218732a25b','94786475-832c-4f97-aab7-bf6fbbe2236b']::uuid[], '[{"step":1,"text":"고구마는 껍질을 벗겨 1cm 크기로 깍둑썰기 한 뒤 삶는다.","imageUrl":null},{"step":2,"text":"양송이버섯과 양파는 굵게 다지고 느타리버섯은 데친다.","imageUrl":null},{"step":3,"text":"냄비에 식용유를 넣어 양파, 고구마, 양송이버섯 순으로 볶는다.","imageUrl":null},{"step":4,"text":"현미 1/2공기와 물 1/2컵을 넣어 믹서에 굵게 간다.","imageUrl":null},{"step":5,"text":"3에 4와 나머지 우유를 넣어 끓인다.","imageUrl":null},{"step":6,"text":"5를 그릇에 담고 고구마, 데친 느타리버섯을 가운데 담는다.","imageUrl":null}]'::jsonb, 'http://www.foodsafetykorea.go.kr/uploadimg/20141117/20141117053334_1416213214596.jpg', 362.9, 37.2, 7.2, 21.4, 161),
  ('784', '두부 채소 볶음밥', '밥', '밥 150g, 두부 70g, 표고버섯(마른것) 10g, 당근 5g, 감자 5g, 청피망 5g, 홍피망 5g, 오이 10g, 애호박 10g, 소금 0.2g  간장 2g, 청고추 0.5g, 홍고추 0.5g, 통깨 0.2g, 참기름 2g, 다시마물 5g', '["밥","두부","표고버섯","당근","감자","청피망","홍피망","오이","애호박","소금","청고추","홍고추","통깨","참기름","다시마물"]'::jsonb, ARRAY['ecb35816-34ae-4c4c-867a-e3f84db92755','4566cac5-9166-4c0d-906a-bfc7360f8f5b','66458b1b-c92f-43fa-8eba-e428892ce88a','e38c12a7-43cb-421a-a36e-7ef0d32517fa','20894da1-739d-4d52-b5fe-4943bd3492d5','df459e6f-3515-45d5-8c9a-9d37b6249379','9dca47c9-8d7a-47b3-b5a7-3c9825cd6e6a','88c94a13-dc8a-4e66-ab19-08fc2ea82c77','2cf0c12b-f248-4012-8f53-303c730a7b3d','30b5d53c-d247-4f04-9b50-c0f728e65cf9','9e00a5b9-84e6-4cdc-afb9-0ee2bd3342fc','0c0ade94-cfd8-4104-b44c-40e942cac482']::uuid[], '[{"step":1,"text":"두부는 으깨서 소창을 이용하여 물기를 짠다.","imageUrl":null},{"step":2,"text":"후라이팬에 납작하게 펴서 노릇하게 굽는다.","imageUrl":null},{"step":3,"text":"구워진 두부를 대충 부서뜨린 후 간장을 넣어서 볶는다.","imageUrl":null},{"step":4,"text":"당근, 감자, 피망, 애호박, 불린 표고버섯, 오이는 작은 정육면체로 썰어 각각 소금간 해서 볶는다.","imageUrl":null},{"step":5,"text":"팬에 감자, 표고버섯, 두부, 밥을 넣고 볶다가 나머지 채소를 넣어 볶는다.","imageUrl":null},{"step":6,"text":"양념장을 만들어 함께 낸다.","imageUrl":null}]'::jsonb, 'http://www.foodsafetykorea.go.kr/uploadimg/20141117/20141117053336_1416213216938.jpg', 322, 60.3, 13.5, 6.5, 213),
  ('1049', '건강 마늘 꿀환', '후식', '마늘 50g, 잣 2g, 꿀 10g, 검은깨 5g, 카스텔라가루 10g', '["마늘","잣","꿀","검은깨","카스텔라가루"]'::jsonb, ARRAY['fc6e31ce-388e-45cd-956b-b238b9134eb1','bbbbd533-8922-4dac-9e4c-cd93ea710c92','286d1783-cd34-4aae-ac8b-006529ec8bc5','9e00a5b9-84e6-4cdc-afb9-0ee2bd3342fc']::uuid[], '[{"step":1,"text":"마늘은 꼭지를 떼고 찜통에 무르도록 찐다.","imageUrl":null},{"step":2,"text":"쪄 낸 마늘을 손절구에 곱게 으깬다","imageUrl":null},{"step":3,"text":"잣은 고깔을 떼고 겉면을 깨끗하게 닦은 뒤 가루를 만든다.","imageUrl":null},{"step":4,"text":"2에 꿀, 검은깨, 잣가루를 넣고 잘 혼합한다.","imageUrl":null},{"step":5,"text":"4에 카스텔라 가루를 넣어 농도를 맞춘다.","imageUrl":null},{"step":6,"text":"반죽을 조금씩 떼어 동그랗게 굴려 꿀환을 만든다.","imageUrl":null}]'::jsonb, 'http://www.foodsafetykorea.go.kr/uploadimg/20141117/20141117053829_1416213509742.jpg', 167, 29.5, 4.8, 4.9, 13),
  ('1051', '과일 샐러드 또띠아', '후식', '자몽 30g, 오렌지 30g, 키위 30g, 사과 30g, 플레인 요구르트 30g, 꿀 5g, 또띠아 45g', '["자몽","오렌지","키위","사과","플레인 요구르트","꿀","또띠아"]'::jsonb, ARRAY['f3ad66d4-1bf6-4c19-90de-6c18147837fd','19eb37dc-2b1c-4e89-a931-31a38ae60561','e748d9a5-9c62-4d33-918a-b1b8e9a1f00b','c85a52b9-c3b4-4a76-951c-bb40edeb3adb','bb41a88a-ea2b-4830-876d-91fe7f640296','286d1783-cd34-4aae-ac8b-006529ec8bc5','7ccfd335-1d3f-4e14-95b3-bd85ed08b72a']::uuid[], '[{"step":1,"text":"자몽은 껍질을 벗겨내고 과육만 0.5cm 주사위모양으로 자른다.","imageUrl":null},{"step":2,"text":"오렌지는 껍질을 벗겨내고 과육만 자몽과 같은 크기로 자른다.","imageUrl":null},{"step":3,"text":"키위도 껍질을 벗겨내고 자몽과 같은 크기로 자른다.","imageUrl":null},{"step":4,"text":"썰어 둔 과일에 플레인 요거트, 꿀을 넣고 버무린다.","imageUrl":null},{"step":5,"text":"또띠아를 반으로 자른다.","imageUrl":null},{"step":6,"text":"버무린 과일을 넣고 말아준다.","imageUrl":null}]'::jsonb, 'http://www.foodsafetykorea.go.kr/uploadimg/20141117/20141117053831_1416213511544.jpg', 277, 58.1, 5.5, 3.5, 84),
  ('1054', '수박 화채', '후식', '찹쌀가루 12g, 물 8g, 수박 180g, 팥 5g, 설탕 5g', '["찹쌀가루","물","수박","팥","설탕"]'::jsonb, ARRAY['4cb11562-015f-4ab5-969f-0ea8483a0b42','94786475-832c-4f97-aab7-bf6fbbe2236b','95fb950a-afb7-4a7f-a6b5-9b912d0e6462','06e6f3e7-0293-469d-a338-11a610f3e71b']::uuid[], '[{"step":1,"text":"찹쌀가루에 뜨거운 물을 넣어 익반죽을 한다.","imageUrl":null},{"step":2,"text":"찹쌀 반죽을 동그랗게 빚는다.","imageUrl":null},{"step":3,"text":"찹쌀 경단을 끓는 물에 삶은 뒤 차갑게 식힌다.","imageUrl":null},{"step":4,"text":"수박은 씨를 제거한 뒤 곱게 갈아 차갑게 식힌다.","imageUrl":null},{"step":5,"text":"그릇에 3과 4를 넣는다.","imageUrl":null},{"step":6,"text":"기호에 따라 팥을 삶아 설탕에 졸여 넣는다.","imageUrl":null}]'::jsonb, 'http://www.foodsafetykorea.go.kr/uploadimg/20141117/20141117053835_1416213515140.jpg', 126, 28.3, 3.4, 0.7, 2),
  ('1055', '우유 생강차', '후식', '우유 180g, 생강 10g, 꿀 6g, 깨소금 3g, 계피가루 1g', '["우유","생강","꿀","깨소금","계피가루"]'::jsonb, ARRAY['e937397f-54e2-49df-997a-f393c58360be','c8e908a8-e613-4f21-a98e-89bb5e2d4bf9','286d1783-cd34-4aae-ac8b-006529ec8bc5','9e00a5b9-84e6-4cdc-afb9-0ee2bd3342fc','5205f393-c02b-4b09-a2d6-42629f7401b9']::uuid[], '[{"step":1,"text":"생강을 깨끗이 씻는다.","imageUrl":null},{"step":2,"text":"생강을 강판에 곱게 간다.","imageUrl":null},{"step":3,"text":"냄비에 우유와 간 생강을 넣고 끓인다.","imageUrl":null},{"step":4,"text":"가장자리가 보글보글 끓어 오르면 불에서 내린다.","imageUrl":null},{"step":5,"text":"믹서에 4를 붓고 깨소금, 꿀을 넣어 간다.","imageUrl":null},{"step":6,"text":"컵에 5를 붓고 계피가루를 살짝 뿌린다.","imageUrl":null}]'::jsonb, 'http://www.foodsafetykorea.go.kr/uploadimg/20150524/20150524053243_1432456363204.jpg', 108, 15.7, 5.9, 2.8, 185),
  ('1056', '레몬 들깨 소스를 품은 떡꼬치', '후식', ' 쌀떡 90g, ghen 10g(1알), 잣 5g(5알), 식용유 30g(2큰술), 꼬치용 꼬치 6개
, 들깨가루 45g(3큰술), 두유 45g(3큰술), 꿀 15g(1큰술), 물 15ml(1큰술), 참기름 7g(1작은술), 레몬즙 7g(1작은술), 검은깨 5g(1작은술)', '["쌀떡","ghen","잣","식용유","꼬치용 꼬치","들깨가루","두유","꿀","물","참기름","레몬즙","검은깨"]'::jsonb, ARRAY['bbbbd533-8922-4dac-9e4c-cd93ea710c92','a7a59e81-de3d-4893-b56a-b2218732a25b','184687ba-0cba-4fec-bb21-33fe300c2073','a4e9789c-3090-43d8-ab14-e4e168f8b910','286d1783-cd34-4aae-ac8b-006529ec8bc5','94786475-832c-4f97-aab7-bf6fbbe2236b','0c0ade94-cfd8-4104-b44c-40e942cac482','6205dc23-e07f-4ddf-bfd8-4f17dfe4db67','9e00a5b9-84e6-4cdc-afb9-0ee2bd3342fc']::uuid[], '[{"step":1,"text":"들깨가루, 검은깨, 두유, 레몬즙, 꿀, 물, 참기름을 섞어 레몬 들깨 소스를 만든다.","imageUrl":null},{"step":2,"text":"떡 군데군데 꼬챙이로 찌르거나 칼집을 넣는다.","imageUrl":null},{"step":3,"text":"팬에 기름을 두르고 160℃ 정도에서 기름이 튀지 않도록 주의하며 떡을 튀긴다.","imageUrl":null},{"step":4,"text":"꼭지를 땐 잣과 호두를 굵게 다진다.","imageUrl":null},{"step":5,"text":"떡은 꼬치에 꽂아 접시에 담는다.","imageUrl":null},{"step":6,"text":"레몬 들깨소스를 바르고 잣, 호두를 고명으로 뿌린다.","imageUrl":null}]'::jsonb, 'http://www.foodsafetykorea.go.kr/uploadimg/20160811/20160811080227_1470913347569.jpg', 735, 100, 12, 32, 573),
  ('1057', '누룽지 요거트 파르페', '후식', ' 밥 210g(1공기)
, 오렌지 40g(1/5개), 사과 30g(1/5개), 요거트 200g(1컵), 블루베리 30g(2큰술)', '["밥","오렌지","사과","요거트","블루베리"]'::jsonb, ARRAY['ecb35816-34ae-4c4c-867a-e3f84db92755','19eb37dc-2b1c-4e89-a931-31a38ae60561','c85a52b9-c3b4-4a76-951c-bb40edeb3adb','bb41a88a-ea2b-4830-876d-91fe7f640296','203b7165-14df-4cb6-b165-e4dadf9a3079']::uuid[], '[{"step":1,"text":"프라이팬에 밥을 얇게 펴 약한 불에서 뚜껑을 덮어 굽는다.","imageUrl":null},{"step":2,"text":"노릇하게 누룽지가 되면 식혀서 굵게 부순다.","imageUrl":null},{"step":3,"text":"오렌지는 깨끗이 씻어 껍질을 벗긴 뒤 먹기 좋은 크기로 자른다.","imageUrl":null},{"step":4,"text":"사과를 깨끗이 씻어 물기를 제거하고 굵게 자른다.","imageUrl":null},{"step":5,"text":"컵에 요거트-오렌지-요거트-누룽지-요거트-사과-요거트-누룽지 순으로 담는다.","imageUrl":null},{"step":6,"text":"마지막에 누룽지와 블루베리로 장식한다.","imageUrl":null}]'::jsonb, 'http://www.foodsafetykorea.go.kr/uploadimg/20160811/20160811080819_1470913699718.jpg', 0, 0, 0, 0, 0),
  ('1058', '자색고구마 호떡', '후식', '반죽: 찹쌀(30g), 자색고구마 20g, 소금(0.2g), 현미휴(3g), 물(17g), 황설탕(7g) 호떡소: 검정깨, 땅콩, 호두(각 2g), 찹쌀가루(0.5g), 계피가루(0.2g)', '["반죽: 찹쌀","자색고구마","소금","현미휴","물","황설탕 호떡소: 검정깨","땅콩","호두","찹쌀가루","계피가루"]'::jsonb, ARRAY['4b4f0113-01cf-4dc6-ae1f-30f09e99746b','2cf0c12b-f248-4012-8f53-303c730a7b3d','94786475-832c-4f97-aab7-bf6fbbe2236b','02c78319-0bf6-45e0-8a7b-7546e1e47ba7','7651578f-1206-499d-a04c-15f034d4cae2','4cb11562-015f-4ab5-969f-0ea8483a0b42','5205f393-c02b-4b09-a2d6-42629f7401b9']::uuid[], '[{"step":1,"text":"찹쌀을 3-5시간 불려둔 뒤 물기를 제거하고 믹서기에 간다.","imageUrl":null},{"step":2,"text":"고구마는 껍질을 벗기고 작게 썰어 찜통에 찐 뒤 말랑말랑해지면 잘 으깨어 반죽하기 편할 정도로 만든다.","imageUrl":null},{"step":3,"text":"검정깨는 믹서기에 곱게 갈고 호두와 땅콩은 잘게 다진 뒤 황설탕과 섞어 호떡소를 만든다.","imageUrl":null},{"step":4,"text":"으깬 고구마에 찹쌀가루를 넣은 뒤 호떡 반죽을 만든다.","imageUrl":null},{"step":5,"text":"완성된 반죽을 적당량 떼어내 동그랗게 빚어 준비해둔 호떡소를 적당량 넣고 봉합한 뒤 납작하게 누른다.","imageUrl":null},{"step":6,"text":"팬에 현미유를 두르고 호떡을 살짝 눌러가면서 앞뒤로 노릇노릇하게 굽는다.","imageUrl":null}]'::jsonb, 'http://www.foodsafetykorea.go.kr/uploadimg/20170106/20170106011651_1483676211608.jpg', 229.2, 38.4, 3.7, 6.5, 71.9),
  ('1059', '청국장지짐 케일쌈밥', '밥', '돼지고기(20g), 청국장(30g), 밥(100g),
케일(50g), 멸치(10g), 무(40g), 양파(80g),
사과(100g)', '["돼지고기","청국장","밥","케일","멸치","무","양파","사과"]'::jsonb, ARRAY['70e914d4-0d03-4202-8b66-81bd8499aa08','6f271236-b557-4340-b3ab-8522098c95df','ecb35816-34ae-4c4c-867a-e3f84db92755','1389717e-81e4-4350-96d4-d627d851aa10','dd2eee03-8bbf-44ff-8a7f-ed1443986711','f80c9a7d-1510-44e2-a82b-28b9f684e191','61a6a6cd-c3d6-4ba2-a033-f6e0b38bc742','c85a52b9-c3b4-4a76-951c-bb40edeb3adb']::uuid[], '[{"step":1,"text":"멸치와 무, 양파 절반, 사과를\r\n끓여 육수를 만든다.","imageUrl":null},{"step":2,"text":"남은 양파와 돼지고기는 곱게\r\n다진다.","imageUrl":null},{"step":3,"text":"청국장에 육수, 다진 양파,\r\n돼지고기를 넣고 볶는다.","imageUrl":null},{"step":4,"text":"케일은 끓는 물에 살짝 데친 뒤\r\n식히고 물기를 없앤다.","imageUrl":null},{"step":5,"text":"밥에 청국장 지짐을 비빈 뒤\r\n케일로 돌돌 말아 반을 자른다.","imageUrl":null},{"step":6,"text":"그릇에 담고 어슷썬 홍고추로\r\n장식한다.","imageUrl":null}]'::jsonb, NULL, 398, 65.4, 19.2, 6.6, 4.3),
  ('1060', '마늘 불고기 덮밥', '밥', '소고기(불고기용, 250g), 쌀(150g),
새송이버섯(50g), 당근(30g), 양파(30g),
대파(20g), 마늘, 배(30g), 진간장(30g),
후춧가루(2g)', '["소고기","쌀","새송이버섯","당근","양파","대파","마늘","배","진간장","후춧가루"]'::jsonb, ARRAY['1c49d1f4-5781-474d-818d-bd7002a4dc0b','a5bc0b46-0192-496a-b429-d2cb90b2bca9','3f94371a-728f-49ae-8ea9-1a1e87b68048','e38c12a7-43cb-421a-a36e-7ef0d32517fa','61a6a6cd-c3d6-4ba2-a033-f6e0b38bc742','4b410642-7bf9-45ad-9055-e7d9a34edaa1','fc6e31ce-388e-45cd-956b-b238b9134eb1','eccf67f1-41f0-4a25-b238-6b9e7332c9e1','f175019d-5a93-4cd4-aabc-e7e79445f15a','bcb746cd-29c8-4bb2-93e4-5832b8adfa94']::uuid[], '[{"step":1,"text":"쌀은 깨끗이 씻고 불려 밥을\r\n짓는다.","imageUrl":null},{"step":2,"text":"소고기는 핏기를 제거하고 버섯,\r\n당근, 양파, 대파는 한 입 크기로\r\n썰어서 준비한다.","imageUrl":null},{"step":3,"text":"절반의 마늘과 진간장, 양파, 배,\r\n후춧가루를 넣고 믹서에 갈아\r\n양념을 만든다.","imageUrl":null},{"step":4,"text":"핏기를 제거한 소고기에 3번의\r\n양념을 넣고 섞는다.","imageUrl":null},{"step":5,"text":"나머지 마늘은 얇게 편썰어\r\n기름에 튀겨 마늘 칩을 만든다.","imageUrl":null},{"step":6,"text":"숙성 시킨 불고기를 팬에 볶고,\r\n그릇에 담은 밥 위에 올리고 마늘\r\n칩으로 장식한다.","imageUrl":null}]'::jsonb, 'http://www.foodsafetykorea.go.kr/uploadimg/cook/10_01060_2.png', 598.4, 85, 24.6, 17.8, 3.1),
  ('1061', '잡곡강정밥', '밥', '잡곡(50g), 찹쌀(50g), 호두(20g),
은행(20g), 밤(20g), 대추고(60g), 꿀(5g),
간장(15g), 소금(2g)', '["잡곡","찹쌀","호두","은행","밤","대추고","꿀","간장","소금"]'::jsonb, ARRAY['a5bc0b46-0192-496a-b429-d2cb90b2bca9','7651578f-1206-499d-a04c-15f034d4cae2','9c201731-bb59-4929-8996-f11933f4f27a','5e4a7ae8-e12e-48b6-88d5-fc3521d3dce8','286d1783-cd34-4aae-ac8b-006529ec8bc5','f175019d-5a93-4cd4-aabc-e7e79445f15a','2cf0c12b-f248-4012-8f53-303c730a7b3d']::uuid[], '[{"step":1,"text":"잡곡과 찹쌀은 물에 씻어 불린 뒤\r\n소금을 넣고 밥을 짓는다.","imageUrl":null},{"step":2,"text":"호두는 껍질을 제거하고 굵게\r\n부숴 마른 팬에 볶는다.","imageUrl":null},{"step":3,"text":"은행은 기름에 볶아 껍질을\r\n제거하고 4등분 한다","imageUrl":null},{"step":4,"text":"생밤은 껍질을 벗기고 작은\r\n주사위 모양으로 자른 뒤 기름에\r\n굽는다.","imageUrl":null},{"step":5,"text":"물 40g에 간장, 대추고, 꿀을 넣고\r\n끓인 뒤 2,3,4번을 넣고 잘 섞는다.","imageUrl":null},{"step":6,"text":"잡곡밥을 넓게 펼친 뒤 5번을\r\n넣고 돌돌 만다.","imageUrl":null}]'::jsonb, 'http://www.foodsafetykorea.go.kr/uploadimg/cook/10_01061_2.png', 594.3, 120.1, 15.2, 5.9, 1.3),
  ('1062', '함박스테이크 볼 밥', '밥', '소고기(60g), 돼지고기(60g), 가래떡(20g),
양파(20g), 새송이버섯(20g),
파프리카(15g), 사과(20g), 배(30g),
고추장(5g), 파(10g), 마늘(5g), 간장(5g),
청주(5g), 후춧가루(0.5g), 참기름(3g)', '["소고기","돼지고기","가래떡","양파","새송이버섯","파프리카","사과","배","고추장","파","마늘","간장","청주","후춧가루","참기름"]'::jsonb, ARRAY['1c49d1f4-5781-474d-818d-bd7002a4dc0b','70e914d4-0d03-4202-8b66-81bd8499aa08','af336608-1eeb-4b10-9a3a-1df0ad140ccb','61a6a6cd-c3d6-4ba2-a033-f6e0b38bc742','3f94371a-728f-49ae-8ea9-1a1e87b68048','5e79d288-1400-4817-bd20-e5e6041821b1','c85a52b9-c3b4-4a76-951c-bb40edeb3adb','eccf67f1-41f0-4a25-b238-6b9e7332c9e1','84b8828b-7396-4dcb-a5d6-44e3cd5a8fdb','4b410642-7bf9-45ad-9055-e7d9a34edaa1','fc6e31ce-388e-45cd-956b-b238b9134eb1','f175019d-5a93-4cd4-aabc-e7e79445f15a','1a3a0bb7-9681-4d47-86ca-c141bcbc92d1','bcb746cd-29c8-4bb2-93e4-5832b8adfa94','0c0ade94-cfd8-4104-b44c-40e942cac482']::uuid[], '[{"step":1,"text":"소고기, 돼지고기, 가래떡, 양파,\r\n새송이버섯, 파는 잘게 다진다","imageUrl":null},{"step":2,"text":"사과와 배는 믹서에 간 뒤 간장,\r\n청주, 다진 마늘, 후춧가루를 넣고\r\n양념장을 만든다.","imageUrl":null},{"step":3,"text":"다진 고기와 양념장을 섞은 뒤\r\n다진 재료를 넣고 잘 치대어 먹기\r\n좋은 크기로 만든다.","imageUrl":null},{"step":4,"text":"팬에 기름을 두르고\r\n함박스테이크를 굽는다.","imageUrl":null},{"step":5,"text":"파프리카는 다지고, 사과, 배는\r\n갈아서 고추장, 간장, 다진 마늘을\r\n섞은 뒤 끓여 소스를 만든다.","imageUrl":null},{"step":6,"text":"밥에 참기름을 넣고\r\n함박스테이크를 담은 뒤 소스를\r\n올려 완성한다.","imageUrl":null}]'::jsonb, 'http://www.foodsafetykorea.go.kr/uploadimg/cook/10_01062_2.png', 439.5, 62.4, 22.3, 11.2, 8),
  ('1063', '곤드레 밥버거', '밥', '쌀(80g), 찹쌀(40g), 흑미(40g), 곤드레나물(50g),
파프리카(30g), 양상추(30g), 감자(20g),
양파(50g), 깻잎(5장), 바나나(1/2개), 김(10g),
호두(10g), 사과(1/4개), 밀가루(30g), 빵가루(50g),
마요네즈(50g), 된장(30g), 식초(30g), 간장(15g),
참기름(15g), 들기름(15g), 소금(0.2g)', '["쌀","찹쌀","흑미","곤드레나물","파프리카","양상추","감자","양파","깻잎","바나나","김","호두","사과","밀가루","빵가루","마요네즈","된장","식초","간장","참기름","들기름","소금"]'::jsonb, ARRAY['a5bc0b46-0192-496a-b429-d2cb90b2bca9','5e79d288-1400-4817-bd20-e5e6041821b1','1389717e-81e4-4350-96d4-d627d851aa10','20894da1-739d-4d52-b5fe-4943bd3492d5','61a6a6cd-c3d6-4ba2-a033-f6e0b38bc742','3c38eb1c-6ef4-4bb8-82be-74f679ce9e91','1a4b39f8-b581-46dc-bd7e-289cd6160711','09229cbc-4574-4002-b726-68c37345bbe9','7651578f-1206-499d-a04c-15f034d4cae2','c85a52b9-c3b4-4a76-951c-bb40edeb3adb','aab3b0b9-d346-4697-a1c8-1b1530153788','45080597-55fa-42dc-aa65-12d7694e4b7e','549c7365-28e9-491f-9040-412558f93a5c','392236b1-82e9-4e38-bd12-6a53b80bf463','6c285c60-022a-4a00-b172-87df97f16a2f','f175019d-5a93-4cd4-aabc-e7e79445f15a','0c0ade94-cfd8-4104-b44c-40e942cac482','f5534afd-2a26-4493-8ec1-fd680dcb3bef','2cf0c12b-f248-4012-8f53-303c730a7b3d']::uuid[], '[{"step":1,"text":"곤드레나물에 들기름, 간장으로\r\n양념하고 쌀, 찹쌀, 흑미와 밥을\r\n지은 뒤 참기름, 소금 간 한다.","imageUrl":null},{"step":2,"text":"식초와 식초2배의 물을 넣고\r\n끓이다가 사과를 한 입 크기로\r\n썰어 끓인다.","imageUrl":null},{"step":3,"text":"감자를 삶아 으깨고, 다진 양파,\r\n호두, 밀가루를 넣고 섞은 뒤 겉에\r\n빵가루를 묻혀 팬에 굽는다.","imageUrl":null},{"step":4,"text":"파프리카는 잘게 채 썬다.","imageUrl":null},{"step":5,"text":"마요네즈, 깻잎, 바나나, 된장을\r\n믹서에 갈아 소스를 만들고\r\n피클을 다져 넣는다.","imageUrl":null},{"step":6,"text":"종이호일을 깔고 중간중간\r\n소스를 뿌리면서 김-양상추-\r\n패티-파프리카-양상추-밥\r\n순으로 얹어 버거를 만든다.","imageUrl":null}]'::jsonb, 'http://www.foodsafetykorea.go.kr/uploadimg/cook/10_01063_2.png', 467, 76.5, 12, 12.6, 22.7),
  ('1064', '대추닭살리조또', '밥', '닭고기(가슴살, 30g), 쌀(50g), 양파(10g),
